export const analyzeReceiptImage = async (base64Image: string): Promise<Partial<Receipt> & { items: Partial<ReceiptItem>[] }> => {
    // 1. Optimize Image for Receipts (Longer, higher resolution)
    const resizedImage = await resizeImage(base64Image, 'receipt');

    const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
    if (!match) throw new Error("Invalid base64 image string.");
    const mimeType = match[1];
    const data = match[2];

    try {
        const gemini = getAiClient();

        const response = await gemini.models.generateContent({
            model: "gemini-2.5-flash",
            contents: {
                parts: [
                    { inlineData: { mimeType, data } },
                    { text: "Analyze this receipt. Extract merchant, date (YYYY-MM-DD), currency (EUR/USD), total. Extract all line items with name, price, quantity (if available, else 1). Categorize each item strictly into one of: 'produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'. Ignore discount lines or subtotal lines." }
                ]
            },
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        merchant_name: { type: Type.STRING },
                        date: { type: Type.STRING },
                        total_amount: { type: Type.NUMBER },
                        currency: { type: Type.STRING },
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    raw_name: { type: Type.STRING },
                                    price: { type: Type.NUMBER },
                                    quantity: { type: Type.NUMBER },
                                    category: { 
                                        type: Type.STRING,
                                        enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other']
                                    }
                                },
                                required: ["raw_name", "price", "category"]
                            }
                        }
                    },
                    required: ["merchant_name", "total_amount", "items"]
                }
            }
        });

        const result = parseJsonFromString(response.text);

        // Ensure date is valid or fallback to today
        let date = result.date;
        if (!date || isNaN(Date.parse(date))) {
            date = new Date().toISOString().split('T')[0];
        }

        return {
            merchant_name: result.merchant_name,
            date: date,
            total_amount: result.total_amount,
            currency: result.currency || 'EUR',
            items: result.items || []
        };

    } catch (error) {
        console.error("Error analyzing receipt:", error);
        throw new Error("Could not analyze receipt.");
    }
}

import { supabase } from './supabaseClient';
import { Receipt, ReceiptItem } from '../types';

// Map AI Output to DB Payload
const mapReceiptToDbPayload = (receipt: Partial<Receipt>, userId: string, householdId?: string) => {
    return {
        uploader_id: userId,
        household_id: householdId || null,
        merchant_name: receipt.merchant_name,
        date: receipt.date || new Date().toISOString(),
        total_amount: receipt.total_amount,
        currency: receipt.currency || 'EUR',
        scanned_at: new Date().toISOString(),
        // image_url handled separately after upload
    };
};

export const createReceipt = async (
    receiptData: Partial<Receipt> & { items: Partial<ReceiptItem>[] }, 
    userId: string, 
    householdId?: string,
    imageUrl?: string
): Promise<Receipt | null> => {

    // 1. Create Receipt Record
    const receiptPayload = {
        ...mapReceiptToDbPayload(receiptData, userId, householdId),
        image_url: imageUrl
    };

    const { data: receipt, error: receiptError } = await supabase
        .from('receipts')
        .insert(receiptPayload)
        .select()
        .single();

    if (receiptError) {
        console.error("Error saving receipt header:", receiptError);
        throw receiptError;
    }

    if (!receipt) return null;

    // 2. Prepare Items
    const itemsPayload = receiptData.items.map(item => ({
        receipt_id: receipt.id,
        raw_name: item.raw_name,
        category: item.category || 'other',
        price: item.price,
        quantity: item.quantity || 1,
        total_price: (item.price || 0) * (item.quantity || 1)
    }));

    // 3. Save Items
    const { error: itemsError } = await supabase
        .from('receipt_items')
        .insert(itemsPayload);

    if (itemsError) {
        console.error("Error saving receipt items:", itemsError);
        // We generally don't delete the receipt header if items fail, 
        // but in a strict transaction we would. Supabase client doesn't support easy transactions yet.
        throw itemsError;
    }

    return { ...receipt, items: itemsPayload };
};

export const fetchReceiptsByHousehold = async (householdId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('household_id', householdId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};

export const fetchReceiptsByUser = async (userId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('uploader_id', userId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};

