                                                    ))}
                                                </div>
                                            </div>
                                        );
                                    })}
                                    {unknownCategories.map(cat => (
                                        <div key={cat} className="space-y-2">
                                            <div className="flex items-center gap-1.5 py-1">
                                                <CategoryOtherIcon className="w-4 h-4 text-gray-500 dark:text-gray-400" />
