import React, { useRef, useEffect, useState } from 'react';
import { useTranslation } from '../i18n/index';
import { XMarkIcon, PencilIcon, BarcodeIcon } from './Icons';
import { useAppSettings } from '../contexts/AppSettingsContext';

interface CameraCaptureProps {
  onCapture: (imageDataUrl: string) => void;
  onClose: () => void;
  mode?: 'main' | 'ingredients' | 'receipt'; // Added 'receipt'
  onSwitchToManual?: () => void;
  onSwitchToBarcode?: () => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture, onClose, mode = 'main', onSwitchToManual, onSwitchToBarcode }) => {
  const { t } = useTranslation();
  const { isBarcodeScannerEnabled } = useAppSettings();
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraReady, setIsCameraReady] = useState(false);

  useEffect(() => {
    let isMounted = true;

    const startCamera = async () => {
      if (streamRef.current) return;

      try {
        const constraints = {
          video: { facingMode: 'environment' },
          audio: false,
        };
        const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
        if (isMounted) {
            streamRef.current = mediaStream;
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream;
                videoRef.current.onloadedmetadata = () => {
                  if(isMounted) setIsCameraReady(true);
                };
            }
        }
      } catch (err: any) {
        console.error("Error accessing rear camera, trying fallback:", err);

        if (err.name === 'NotAllowedError') {
            if (isMounted) setError(t('camera.error.permission'));
            return;
        }

        try {
          const fallbackConstraints = { video: true, audio: false };
          const mediaStream = await navigator.mediaDevices.getUserMedia(fallbackConstraints);
          if (isMounted) {
            streamRef.current = mediaStream;
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream;
                videoRef.current.onloadedmetadata = () => {
                  if(isMounted) setIsCameraReady(true);
                };
            }
          }
        } catch (fallbackErr: any) {
          if (isMounted) {
            if (fallbackErr.name === 'NotAllowedError') {
                setError(t('camera.error.permission'));
            } else {
                setError(t('camera.error'));
            }
          }
        }
      }
    };

    startCamera();

    return () => {
      isMounted = false;
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
    };
  }, [t]);

  const handleCapture = () => {
    if (videoRef.current && canvasRef.current && isCameraReady) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      if (ctx) {
        // Calculate crop dimensions based on the overlay aspect ratio
        const videoW = video.videoWidth;
        const videoH = video.videoHeight;
        const minDim = Math.min(videoW, videoH);

        let cropW, cropH, startX, startY;

        if (mode === 'main') {
            // Square crop for products
            const cropSize = minDim * 0.8; 
            cropW = cropSize;
            cropH = cropSize;
        } else if (mode === 'ingredients') {
            // Taller rectangle for ingredients
            cropW = minDim * 0.8;
            cropH = cropW * 1.33;
            if (cropH > videoH * 0.9) {
                cropH = videoH * 0.9;
                cropW = cropH / 1.33;
            }
        } else {
            // Receipt Mode: Very tall rectangle (approx 1:2 ratio)
            // We want to capture as much height as possible
            cropH = videoH * 0.9; 
            cropW = cropH * 0.5; // 1:2 Aspect Ratio

            // Ensure width doesn't exceed video width
            if (cropW > videoW * 0.9) {
                cropW = videoW * 0.9;
                cropH = cropW * 2;
            }
        }

        // Center the crop area
        startX = (videoW - cropW) / 2;
        startY = (videoH - cropH) / 2;

        // Set canvas size to the crop size
        canvas.width = cropW;
        canvas.height = cropH;

        // Handle mirroring if user facing camera
        const isUserFacing = streamRef.current?.getVideoTracks()[0]?.getSettings().facingMode === 'user';

        if (isUserFacing) {
            ctx.translate(canvas.width, 0);
            ctx.scale(-1, 1);
        }

        // Draw only the cropped area
        ctx.drawImage(
            video, 
            startX, startY, cropW, cropH, // Source coords
            0, 0, canvas.width, canvas.height // Dest coords
        );

        const imageDataUrl = canvas.toDataURL('image/jpeg', 0.9);
        onCapture(imageDataUrl);
      }
    }
  };

  const getOverlayStyle = () => {
      switch(mode) {
          case 'main': return 'aspect-square w-[80vw] max-w-[80vh] rounded-xl';
          case 'ingredients': return 'aspect-[3/4] w-[70vw] max-w-[60vh] rounded-lg';
          case 'receipt': return 'aspect-[1/2] h-[80vh] max-w-[90vw] rounded-lg border-dashed';
          default: return 'aspect-square w-[80vw]';
      }
  };

  const getInstructionText = () => {
      switch(mode) {
          case 'main': return 'Produkt hier platzieren';
          case 'ingredients': return 'Zutatenliste hier platzieren';
          case 'receipt': return 'Kassenbon lang platzieren';
          default: return '';
      }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-95 flex flex-col items-center justify-center z-50">
      <div className="absolute top-0 left-0 w-full p-4 z-20 flex justify-between items-center">
         <h3 className="text-lg font-bold text-white drop-shadow-md">{t('camera.title')}</h3>
         <button onClick={onClose} className="text-white hover:text-gray-300 p-2">
            <XMarkIcon className="w-8 h-8" />
         </button>
      </div>

      {error ? (
        <div className="text-red-400 p-8 text-center max-w-xs">{error}</div>
      ) : (
        <div className="relative w-full h-full flex items-center justify-center overflow-hidden">
          {/* Video Layer */}
          <video
            ref={videoRef}
            autoPlay
            playsInline
            muted
            className="absolute inset-0 w-full h-full object-cover"
          />

          {/* Dark Overlay */}
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
             <div 
                className={`relative border-2 border-white/80 shadow-[0_0_0_9999px_rgba(0,0,0,0.7)] transition-all duration-300 ${getOverlayStyle()}`}
             >
                {/* Corner markers */}
                <div className="absolute top-[-2px] left-[-2px] w-6 h-6 border-t-4 border-l-4 border-indigo-500 rounded-tl-xl"></div>
                <div className="absolute top-[-2px] right-[-2px] w-6 h-6 border-t-4 border-r-4 border-indigo-500 rounded-tr-xl"></div>
                <div className="absolute bottom-[-2px] left-[-2px] w-6 h-6 border-b-4 border-l-4 border-indigo-500 rounded-bl-xl"></div>
                <div className="absolute bottom-[-2px] right-[-2px] w-6 h-6 border-b-4 border-r-4 border-indigo-500 rounded-br-xl"></div>

                {/* Helper text */}
                <div className="absolute bottom-4 left-0 right-0 text-center">
                    <span className="text-white/80 text-xs bg-black/40 px-2 py-1 rounded-full backdrop-blur-sm">
                        {getInstructionText()}
                    </span>
                </div>
             </div>
          </div>

          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}

      {/* Footer Controls */}
      <div className="absolute bottom-0 left-0 w-full p-8 z-20 flex justify-between items-center bg-gradient-to-t from-black/80 to-transparent">

        <div className="flex-1 flex justify-start">
            {onSwitchToManual && (
                <button
                    onClick={onSwitchToManual}
                    className="flex flex-col items-center gap-1 text-white/70 hover:text-white transition-colors p-2"
                >
                    <div className="p-2 bg-white/10 rounded-full backdrop-blur-md">
                        <PencilIcon className="w-6 h-6" />
                    </div>
                    <span className="text-[10px] font-medium hidden sm:block">Manuell</span>
                </button>
            )}
        </div>

        <button
          onClick={handleCapture}
          disabled={!isCameraReady || !!error}
          className="w-20 h-20 bg-white rounded-full border-4 border-gray-300 shadow-lg flex items-center justify-center hover:bg-gray-100 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed mx-4"
          aria-label={t('camera.captureButton')}
        >
            <div className="w-16 h-16 bg-white rounded-full border-2 border-black"></div>
        </button>

        <div className="flex-1 flex justify-end">
            {isBarcodeScannerEnabled && onSwitchToBarcode && (
                <button
                    onClick={onSwitchToBarcode}
                    className="flex flex-col items-center gap-1 text-white/70 hover:text-white transition-colors p-2"
                >
                    <div className="p-2 bg-white/10 rounded-full backdrop-blur-md">
                        <BarcodeIcon className="w-6 h-6" />
                    </div>
                    <span className="text-[10px] font-medium hidden sm:block">Barcode</span>
                </button>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Receipt, ReceiptItem, GroceryCategory } from '../../types';
import { XMarkIcon, SpinnerIcon, CategoryProduceIcon, CategoryBakeryIcon, CategoryMeatIcon, CategoryDairyIcon, CategoryPantryIcon, CategoryFrozenIcon, CategorySnacksIcon, CategoryBeveragesIcon, CategoryHouseholdIcon, CategoryPersonalCareIcon, CategoryOtherIcon, CategoryRestaurantIcon, CheckCircleIcon, TrashIcon, PlusCircleIcon } from '../Icons';
import { useTranslation } from '../../i18n/index';

interface ReceiptReviewModalProps {
    receiptData: Partial<Receipt> & { items: Partial<ReceiptItem>[] };
    onSave: (data: Partial<Receipt> & { items: Partial<ReceiptItem>[] }) => Promise<void>;
    onClose: () => void;
    isLoading?: boolean;
}

const CategoryIconMap: Record<GroceryCategory, React.FC<{ className?: string }>> = {
    'produce': CategoryProduceIcon,
    'bakery': CategoryBakeryIcon,
    'meat_fish': CategoryMeatIcon,
    'dairy_eggs': CategoryDairyIcon,
    'pantry': CategoryPantryIcon,
    'frozen': CategoryFrozenIcon,
    'snacks': CategorySnacksIcon,
    'beverages': CategoryBeveragesIcon,
    'household': CategoryHouseholdIcon,
    'personal_care': CategoryPersonalCareIcon,
    'restaurant_food': CategoryRestaurantIcon,
    'other': CategoryOtherIcon,
};

const CATEGORIES: GroceryCategory[] = ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'other'];

export const ReceiptReviewModal: React.FC<ReceiptReviewModalProps> = ({ receiptData, onSave, onClose, isLoading }) => {
    const { t } = useTranslation();
    const [data, setData] = useState(receiptData);
    const [isSaving, setIsSaving] = useState(false);

    // Header Updates
    const updateHeader = (key: keyof Receipt, value: any) => {
        setData(prev => ({ ...prev, [key]: value }));
    };

    // Item Updates
    const updateItem = (index: number, field: keyof ReceiptItem, value: any) => {
        const newItems = [...(data.items || [])];
        newItems[index] = { ...newItems[index], [field]: value };
        // Recalculate total if price/qty changes
        if (field === 'price' || field === 'quantity') {
            const p = field === 'price' ? parseFloat(value) || 0 : newItems[index].price || 0;
            const q = field === 'quantity' ? parseFloat(value) || 1 : newItems[index].quantity || 1;
            newItems[index].total_price = p * q;
        }

        // Update header total if items change
        const newTotal = newItems.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);
        setData(prev => ({ ...prev, items: newItems, total_amount: parseFloat(newTotal.toFixed(2)) }));
    };

    const deleteItem = (index: number) => {
        const newItems = [...(data.items || [])];
        newItems.splice(index, 1);
        const newTotal = newItems.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);
        setData(prev => ({ ...prev, items: newItems, total_amount: parseFloat(newTotal.toFixed(2)) }));
    };

    const addItem = () => {
        const newItem: Partial<ReceiptItem> = {
            raw_name: '',
            price: 0,
            quantity: 1,
            category: 'other'
        };
        setData(prev => ({ ...prev, items: [...(prev.items || []), newItem] }));
    };

    const handleSave = async () => {
        if (!data.merchant_name || !data.total_amount) {
            alert("Merchant and Total are required.");
            return;
        }
        setIsSaving(true);
        await onSave(data);
        setIsSaving(false);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50 p-0 sm:p-4 animate-fade-in">
            <div className="bg-white dark:bg-gray-900 w-full h-full sm:h-[90vh] sm:max-w-2xl sm:rounded-xl shadow-2xl flex flex-col overflow-hidden">

                {/* Header */}
                <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 pt-safe-top">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white">Beleg prüfen</h2>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-full text-gray-500">
                        <XMarkIcon className="w-6 h-6" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-4 space-y-6">
                    {/* Meta Data Card */}
                    <div className="bg-indigo-50 dark:bg-indigo-900/10 p-4 rounded-xl border border-indigo-100 dark:border-indigo-800/30 grid grid-cols-2 gap-4">
                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Geschäft</label>
                            <input 
                                type="text" 
                                value={data.merchant_name || ''} 
                                onChange={(e) => updateHeader('merchant_name', e.target.value)}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2 text-lg font-bold"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Datum</label>
                            <input 
                                type="date" 
                                value={data.date?.split('T')[0] || ''} 
                                onChange={(e) => updateHeader('date', e.target.value)}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Gesamt ({data.currency})</label>
                            <input 
                                type="number" 
                                step="0.01"
                                value={data.total_amount || ''} 
                                onChange={(e) => updateHeader('total_amount', parseFloat(e.target.value))}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2 text-right font-mono"
                            />
                        </div>
                    </div>

                    {/* Items List */}
                    <div className="space-y-3">
                        <div className="flex justify-between items-center px-1">
                            <h3 className="font-bold text-gray-700 dark:text-gray-300">Artikel ({data.items?.length || 0})</h3>
                            <button onClick={addItem} className="text-indigo-600 dark:text-indigo-400 text-sm font-semibold flex items-center gap-1">
                                <PlusCircleIcon className="w-4 h-4" /> Hinzufügen
                            </button>
                        </div>

                        {data.items?.map((item, idx) => {
                            const CatIcon = CategoryIconMap[item.category || 'other'];
                            return (
                                <div key={idx} className="flex items-center gap-2 bg-white dark:bg-gray-800/50 p-2 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                                    {/* Category Selector (Cycle through or simple dropdown) */}
                                    <div className="relative group shrink-0">
                                        <button className="p-2 bg-gray-100 dark:bg-gray-700 rounded-full text-gray-500">
                                            <CatIcon className="w-5 h-5" />
                                        </button>
                                        {/* Simple hover/focus dropdown for category */}
                                        <select 
                                            className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                                            value={item.category || 'other'}
                                            onChange={(e) => updateItem(idx, 'category', e.target.value)}
                                        >
                                            {CATEGORIES.map(cat => (
                                                <option key={cat} value={cat}>{t(`category.${cat}`)}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {/* Name & Qty */}
                                    <div className="flex-1 min-w-0 flex flex-col gap-1">
                                        <input 
                                            type="text" 
                                            value={item.raw_name || ''} 
                                            onChange={(e) => updateItem(idx, 'raw_name', e.target.value)}
                                            className="w-full bg-transparent border-none p-0 text-sm font-medium focus:ring-0 placeholder-gray-400"
                                            placeholder="Artikelname"
                                        />
                                        <div className="flex items-center gap-2 text-xs text-gray-400">
                                            <span>Menge:</span>
                                            <input 
                                                type="number" 
                                                value={item.quantity || 1} 
                                                onChange={(e) => updateItem(idx, 'quantity', parseFloat(e.target.value))}
                                                className="w-12 bg-gray-100 dark:bg-gray-700 rounded px-1 py-0.5 text-center"
                                            />
                                        </div>
                                    </div>

                                    {/* Price & Delete */}
                                    <div className="flex flex-col items-end gap-1">
                                        <input 
                                            type="number" 
                                            step="0.01"
                                            value={item.price || ''} 
                                            onChange={(e) => updateItem(idx, 'price', parseFloat(e.target.value))}
                                            className="w-20 bg-transparent border-none p-0 text-sm font-bold text-right focus:ring-0"
                                            placeholder="0.00"
                                        />
                                        <button onClick={() => deleteItem(idx)} className="text-red-400 hover:text-red-500 p-1">
                                            <TrashIcon className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Footer Actions */}
                <div className="p-4 border-t border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 pb-safe-bottom">
                    <button 
                        onClick={handleSave} 
                        disabled={isSaving || isLoading}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-xl shadow-md transition-transform active:scale-95 flex items-center justify-center gap-2 disabled:bg-indigo-400"
                    >
                        {isSaving || isLoading ? <SpinnerIcon className="w-5 h-5" /> : <CheckCircleIcon className="w-5 h-5" />}
                        {isSaving ? "Speichere..." : "Speichern & Analysieren"}
                    </button>
                </div>
            </div>
        </div>
    );
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { Receipt, ReceiptItem, GroceryCategory } from '../types';
import { User } from '@supabase/supabase-js';

export const useReceipts = (user: User | null, householdId: string | null | undefined) => {
    const [receipts, setReceipts] = useState<Receipt[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const fetchReceipts = useCallback(async () => {
        if (!user) return;
        setIsLoading(true);
        setError(null);
        try {
            let query = supabase.from('receipts').select(`
                *,
                items:receipt_items(*)
            `).order('date', { ascending: false });

            if (householdId) {
                query = query.eq('household_id', householdId);
            } else {
                query = query.eq('uploader_id', user.id);
            }

            const { data, error } = await query;
            if (error) throw error;
            setReceipts(data || []);
        } catch (err: any) {
            console.error("Error fetching receipts:", err);
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    }, [user, householdId]);

    useEffect(() => {
        fetchReceipts();
    }, [fetchReceipts]);

    const getMonthlySpending = useCallback(() => {
        const monthlyData: Record<string, number> = {};
        const now = new Date();
        const monthNames = ["Jan", "Feb", "Mär", "Apr", "Mai", "Jun", "Jul", "Aug", "Sep", "Okt", "Nov", "Dez"];

        // Initialize last 6 months with 0
        for (let i = 5; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            const key = `${monthNames[d.getMonth()]}`; 
            monthlyData[key] = 0; // Initialize order matters
        }

        receipts.forEach(receipt => {
            const date = new Date(receipt.date);
            const key = monthNames[date.getMonth()];
            // Only count if it falls within our tracked keys (approx last year logic for simplicity in chart)
            if (monthlyData[key] !== undefined) {
                monthlyData[key] += receipt.total_amount;
            }
        });

        // Convert to array for Recharts/SVG
        return Object.entries(monthlyData).map(([label, value]) => ({ 
            label, 
            value,
            active: label === monthNames[now.getMonth()]
        }));
    }, [receipts]);

    const getCategoryBreakdown = useCallback(() => {
        const catData: Record<string, number> = {};

        receipts.forEach(receipt => {
            if (receipt.items) {
                receipt.items.forEach(item => {
                    const cat = item.category || 'other';
                    const amount = (item.price || 0) * (item.quantity || 1);
                    catData[cat] = (catData[cat] || 0) + amount;
                });
            }
        });

        const categoryColors: Record<string, string> = {
            'produce': '#4ade80',
            'bakery': '#fbbf24',
            'meat_fish': '#f87171',
            'dairy_eggs': '#facc15',
            'pantry': '#fb923c',
            'frozen': '#38bdf8',
            'snacks': '#f472b6',
            'beverages': '#60a5fa',
            'household': '#94a3b8',
            'personal_care': '#c084fc',
            'restaurant_food': '#2dd4bf',
            'other': '#9ca3af',
        };

        return Object.entries(catData)
            .map(([cat, value]) => ({
                label: cat, // Will translate in component
                value,
                color: categoryColors[cat] || '#ccc'
            }))
            .sort((a, b) => b.value - a.value); // Sort highest spend first
    }, [receipts]);

    return {
        receipts,
        isLoading,
        error,
        refreshReceipts: fetchReceipts,
        getMonthlySpending,
        getCategoryBreakdown
    };
};

