import { supabase } from './supabaseClient';
import { Receipt, ReceiptItem } from '../types';

// Map AI Output to DB Payload
const mapReceiptToDbPayload = (receipt: Partial<Receipt>, userId: string, householdId?: string) => {
    return {
        uploader_id: userId,
        household_id: householdId || null,
        merchant_name: receipt.merchant_name || 'Unknown Store', // Fallback
        date: receipt.date || new Date().toISOString(),
        total_amount: typeof receipt.total_amount === 'number' ? receipt.total_amount : 0, // Ensure number
        currency: receipt.currency || 'EUR',
        scanned_at: new Date().toISOString(),
        // image_url handled separately after upload
    };
};

export const createReceipt = async (
    receiptData: Partial<Receipt> & { items: Partial<ReceiptItem>[] }, 
    userId: string, 
    householdId?: string,
    imageUrl?: string
): Promise<Receipt | null> => {

    // 1. Create Receipt Record
    const receiptPayload = {
        ...mapReceiptToDbPayload(receiptData, userId, householdId),
        image_url: imageUrl
    };

    const { data: receipt, error: receiptError } = await supabase
        .from('receipts')
        .insert(receiptPayload)
        .select()
        .single();

    if (receiptError) {
        console.error("Error saving receipt header:", receiptError);
        throw new Error(`Receipt Header Save Failed: ${receiptError.message}`);
    }

    if (!receipt) return null;

    // 2. Prepare Items with strict sanitization
    // Database strictly expects numbers for price/qty, usually NOT NULL.
    const itemsPayload = receiptData.items.map(item => {
        const safePrice = typeof item.price === 'number' ? item.price : 0;
        const safeQty = typeof item.quantity === 'number' ? item.quantity : 1;

        return {
            receipt_id: receipt.id,
            raw_name: item.raw_name || 'Unknown Item',
            category: item.category || 'other',
            price: safePrice,
            quantity: safeQty,
            total_price: safePrice * safeQty
        };
    });

    // 3. Save Items
    if (itemsPayload.length > 0) {
        const { error: itemsError } = await supabase
            .from('receipt_items')
            .insert(itemsPayload);

        if (itemsError) {
            console.error("Error saving receipt items:", itemsError);
            // We generally don't delete the receipt header if items fail, 
            // but in a strict transaction we would. Supabase client doesn't support easy transactions yet.
            throw new Error(`Receipt Items Save Failed: ${itemsError.message}`);
        }
    }

    return { ...receipt, items: itemsPayload };
};

export const updateReceipt = async (
    receiptId: string, 
    updates: Partial<Receipt>
): Promise<Receipt> => {
    // Only allow updating specific header fields to maintain data integrity
    const safeUpdates = {
        merchant_name: updates.merchant_name,
        date: updates.date,
        total_amount: updates.total_amount,
        currency: updates.currency
    };

    const { data, error } = await supabase
        .from('receipts')
        .update(safeUpdates)
        .eq('id', receiptId)
        .select()
        .single();

    if (error) throw error;
    return data;
};

export const deleteReceipt = async (receiptId: string): Promise<void> => {
    const { error } = await supabase
        .from('receipts')
        .delete()
        .eq('id', receiptId);

    if (error) throw error;
};

export const fetchReceiptsByHousehold = async (householdId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('household_id', householdId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};

export const fetchReceiptsByUser = async (userId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('uploader_id', userId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { Receipt, ReceiptItem, GroceryCategory } from '../types';
import { User } from '@supabase/supabase-js';
import { updateReceipt as apiUpdateReceipt, deleteReceipt as apiDeleteReceipt } from '../services/receiptService';

export const useReceipts = (user: User | null, householdId: string | null | undefined) => {
    const [receipts, setReceipts] = useState<Receipt[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const fetchReceipts = useCallback(async () => {
        if (!user) return;
        setIsLoading(true);
        setError(null);
        try {
            let query = supabase.from('receipts').select(`
                *,
                items:receipt_items(*)
            `).order('date', { ascending: false });

            if (householdId) {
                query = query.eq('household_id', householdId);
            } else {
                query = query.eq('uploader_id', user.id);
            }

            const { data, error } = await query;
            if (error) throw error;
            setReceipts(data || []);
        } catch (err: any) {
            console.error("Error fetching receipts:", err);
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    }, [user, householdId]);

    useEffect(() => {
        fetchReceipts();
    }, [fetchReceipts]);

    const updateReceipt = useCallback(async (id: string, updates: Partial<Receipt>) => {
        try {
            const updated = await apiUpdateReceipt(id, updates);
            // Optimistic update
            setReceipts(prev => prev.map(r => r.id === id ? { ...r, ...updated } : r));
            return true;
        } catch (e: any) {
            console.error("Failed to update receipt:", e);
            setError(e.message);
            return false;
        }
    }, []);

    const deleteReceipt = useCallback(async (id: string) => {
        try {
            await apiDeleteReceipt(id);
            // Optimistic update
            setReceipts(prev => prev.filter(r => r.id !== id));
            return true;
        } catch (e: any) {
            console.error("Failed to delete receipt:", e);
            setError(e.message);
            return false;
        }
    }, []);

    const getMonthlySpending = useCallback(() => {
        const monthlyData: Record<string, number> = {};
        const now = new Date();
        const monthNames = ["Jan", "Feb", "Mär", "Apr", "Mai", "Jun", "Jul", "Aug", "Sep", "Okt", "Nov", "Dez"];

        // Initialize last 6 months with 0
        for (let i = 5; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            const key = `${monthNames[d.getMonth()]}`; 
            monthlyData[key] = 0; // Initialize order matters
        }

        receipts.forEach(receipt => {
            const date = new Date(receipt.date);
            const key = monthNames[date.getMonth()];
            // Only count if it falls within our tracked keys (approx last year logic for simplicity in chart)
            if (monthlyData[key] !== undefined) {
                monthlyData[key] += receipt.total_amount;
            }
        });

        // Convert to array for Recharts/SVG
        return Object.entries(monthlyData).map(([label, value]) => ({ 
            label, 
            value,
            active: label === monthNames[now.getMonth()]
        }));
    }, [receipts]);

    const getCategoryBreakdown = useCallback(() => {
        const catData: Record<string, number> = {};

        receipts.forEach(receipt => {
            if (receipt.items) {
                receipt.items.forEach(item => {
                    const cat = item.category || 'other';
                    const amount = (item.price || 0) * (item.quantity || 1);
                    catData[cat] = (catData[cat] || 0) + amount;
                });
            }
        });

        const categoryColors: Record<string, string> = {
            'produce': '#4ade80',
            'bakery': '#fbbf24',
            'meat_fish': '#f87171',
            'dairy_eggs': '#facc15',
            'pantry': '#fb923c',
            'frozen': '#38bdf8',
            'snacks': '#f472b6',
            'beverages': '#60a5fa',
            'household': '#94a3b8',
            'personal_care': '#c084fc',
            'restaurant_food': '#2dd4bf',
            'other': '#9ca3af',
        };

        return Object.entries(catData)
            .map(([cat, value]) => ({
                label: cat, // Will translate in component
                value,
                color: categoryColors[cat] || '#ccc'
            }))
            .sort((a, b) => b.value - a.value); // Sort highest spend first
    }, [receipts]);

    return {
        receipts,
        isLoading,
        error,
        refreshReceipts: fetchReceipts,
        updateReceipt,
        deleteReceipt,
        getMonthlySpending,
        getCategoryBreakdown
    };
};

