export const FoodItemDetailView: React.FC<FoodItemDetailViewProps> = ({ item, onImageClick }) => {
  const { t, language } = useTranslation();
  const { user } = useAuth();
  const displayItem = useTranslatedItem(item);
  const [priceHistory, setPriceHistory] = useState<PricePoint[]>([]);
  const [isHistoryLoading, setIsHistoryLoading] = useState(false);

  // Fetch History Logic
  useEffect(() => {
      let isMounted = true;
      const loadHistory = async () => {
          if (!user || !displayItem) return;

          // Only fetch for products, not dishes (dishes have specific price field, but receipts are usually grocery)
          if (displayItem.itemType !== 'product' && displayItem.itemType !== 'drugstore') return;

          setIsHistoryLoading(true);
          try {
              const history = await fetchPriceHistory(displayItem.name, user.id);
              if (isMounted) setPriceHistory(history);
          } catch (e) {
              console.error("Failed to load price history", e);
          } finally {
              if (isMounted) setIsHistoryLoading(false);
          }
      };
      loadHistory();
      return () => { isMounted = false; };
  }, [user, displayItem?.name, displayItem?.itemType]); // Dependency on name is key

  if (!displayItem) {
    return null; // Or a loading state
  }

  const isConsumableOrDrugstore = displayItem.itemType === 'product' || displayItem.itemType === 'drugstore';
  const hasAttributes = isConsumableOrDrugstore && (displayItem.isLactoseFree || displayItem.isVegan || displayItem.isGlutenFree);
  const hasAllergens = isConsumableOrDrugstore && displayItem.allergens && displayItem.allergens.length > 0;
  const hasIngredients = isConsumableOrDrugstore && displayItem.ingredients && displayItem.ingredients.length > 0;
  const hasTags = displayItem.tags && displayItem.tags.length > 0;

  return (
    <div className="space-y-6 text-sm">
      {/* Header with Image, Name, Rating */}
      <div className="flex items-start gap-4">
        {displayItem.image && (
          <div 
            className="w-24 h-24 flex-shrink-0 rounded-md overflow-hidden cursor-pointer group shadow-sm border border-gray-100 dark:border-gray-700"
            onClick={() => displayItem.image && onImageClick(displayItem.image)}
          >
            <img src={displayItem.image} alt={displayItem.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
          </div>
        )}
        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between">
             <h3 className="text-xl font-bold text-gray-900 dark:text-white leading-tight">{displayItem.name}</h3>
             {displayItem.itemType === 'drugstore' && (
                 <div className="bg-purple-100 dark:bg-purple-900/50 p-1 rounded-full text-purple-600 dark:text-purple-300 shrink-0" title={t('modal.itemType.drugstore')}>
                     <BeakerIcon className="w-5 h-5" />
                 </div>
             )}
          </div>

          {/* Purchase location for products/drugstore */}
          {isConsumableOrDrugstore && displayItem.purchaseLocation && displayItem.purchaseLocation.length > 0 && (
            <div className="flex items-center gap-2 mt-2 flex-wrap">
               {displayItem.purchaseLocation.map((loc, idx) => (
                   <StoreLogo key={idx} name={loc} size="sm" showName={true} className="bg-gray-100 dark:bg-gray-700 rounded-full pr-2 py-0.5 border border-gray-200 dark:border-gray-600" />
               ))}
            </div>
          )}

          {/* Restaurant details for dishes */}
          {displayItem.itemType === 'dish' && (
            <div className="mt-1 space-y-1">
              {displayItem.restaurantName && (
                <div className="flex items-center gap-1.5 text-sm text-gray-500 dark:text-gray-400">
                  <BuildingStorefrontIcon className="w-4 h-4" />
                  <p className="truncate italic" title={displayItem.restaurantName}>{displayItem.restaurantName}</p>
                </div>
              )}
              {displayItem.cuisineType && (
                <div className="flex items-center gap-1.5 text-sm text-gray-500 dark:text-gray-400">
                  <DocumentTextIcon className="w-4 h-4" />
                  <p className="truncate" title={displayItem.cuisineType}>{displayItem.cuisineType}</p>
                </div>
              )}
            </div>
          )}

          {/* Unified Price Display for All Types */}
          {typeof displayItem.price === 'number' && (
            <div className="flex items-center gap-1 mt-1 text-sm text-gray-700 dark:text-gray-200 font-bold">
              <span>{displayItem.price.toLocaleString(language === 'de' ? 'de-DE' : 'en-US', { style: 'currency', currency: language === 'de' ? 'EUR' : 'USD' })}</span>
            </div>
          )}

          <div className="flex items-center mt-2">
            {[1, 2, 3, 4, 5].map(star => (
              <StarIcon key={star} className={`w-5 h-5 ${displayItem.rating >= star ? 'text-yellow-400' : 'text-gray-300 dark:text-gray-600'}`} filled={displayItem.rating >= star} />
            ))}

            {displayItem.itemType === 'product' && (
                <div className="flex items-center gap-2 ml-3">
                    {displayItem.nutriScore && (
                    <div className={`text-xs w-6 h-6 rounded-full text-white font-bold flex items-center justify-center flex-shrink-0 shadow-sm ${nutriScoreColors[displayItem.nutriScore]}`}>
                        {displayItem.nutriScore}
                    </div>
                    )}
                    {displayItem.calories && (
                        <div className="text-xs bg-orange-100 dark:bg-orange-900/50 text-orange-800 dark:text-orange-200 px-2 py-0.5 rounded-full font-semibold whitespace-nowrap border border-orange-200 dark:border-orange-800">
                            🔥 {displayItem.calories} kcal
                        </div>
                    )}
                </div>
            )}
          </div>
           <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 mt-2">
              <span className="font-semibold text-xs uppercase tracking-wide opacity-70">{t('detail.status')}:</span>
              <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-xs font-medium border ${displayItem.isFamilyFavorite ? 'bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300 border-green-200 dark:border-green-800' : 'bg-gray-100 dark:bg-gray-700/50 text-gray-700 dark:text-gray-300 border-gray-200 dark:border-gray-600'}`}>
                  {displayItem.isFamilyFavorite ? <UserGroupIcon className="w-3 h-3" /> : <LockClosedIcon className="w-3 h-3" />}
                  <span>{t(displayItem.isFamilyFavorite ? 'detail.statusFamilyFavorite' : 'detail.statusPrivate')}</span>
              </div>
          </div>
        </div>
      </div>

      {/* PRICE WATCH CHART (New Feature) */}
      {!isHistoryLoading && isConsumableOrDrugstore && (
          <div className="animate-fade-in">
              <PriceHistoryChart 
                  history={priceHistory} 
                  currentPrice={displayItem.price} 
                  itemName={displayItem.name} 
              />
          </div>
      )}

      {/* Notes */}
      {displayItem.notes && (
        <div className="bg-yellow-50 dark:bg-yellow-900/10 p-3 rounded-lg border border-yellow-100 dark:border-yellow-800/30">
          <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-1 text-xs uppercase tracking-wide">{t('detail.notesTitle')}</h4>
          <p className="text-gray-700 dark:text-gray-300 whitespace-pre-wrap leading-relaxed">{displayItem.notes}</p>
        </div>
      )}

      {/* Tags */}
      {hasTags && (
        <div>
          <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-2 text-xs uppercase tracking-wide">{t('detail.tagsTitle')}</h4>
          <div className="flex flex-wrap gap-2">
            {displayItem.tags!.map(tag => (
              <span key={tag} className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300 text-xs font-medium px-2.5 py-1 rounded-full shadow-sm">{tag}</span>
            ))}
          </div>
        </div>
      )}

      {isConsumableOrDrugstore && (hasAttributes || hasAllergens) && (
        <div className="grid grid-cols-1 gap-4 pt-2">
          {hasAttributes && (
            <div className="bg-blue-50 dark:bg-blue-900/10 p-3 rounded-lg border border-blue-100 dark:border-blue-800/30">
              <h4 className="font-bold text-blue-900 dark:text-blue-200 mb-2 text-xs uppercase tracking-wide">
                  {t(displayItem.itemType === 'drugstore' ? 'form.attributes.title' : 'detail.dietaryTitle')}
              </h4>
              <div className="flex items-center gap-3">
                {displayItem.isLactoseFree && <DietaryIcon type="lactoseFree" className="w-8 h-8" />}
                {displayItem.isVegan && <DietaryIcon type="vegan" className="w-8 h-8" />}
                {displayItem.isGlutenFree && <DietaryIcon type="glutenFree" className="w-8 h-8" />}
              </div>
            </div>
          )}
          {hasAllergens && (
            <div className="bg-red-50 dark:bg-red-900/10 p-3 rounded-lg border border-red-100 dark:border-red-800/30">
              <h4 className="font-bold text-red-900 dark:text-red-200 mb-2 text-xs uppercase tracking-wide">{t('detail.allergensTitle')}</h4>
              <AllergenDisplay allergens={displayItem.allergens!} />
            </div>
          )}
        </div>
      )}

      {/* Ingredients */}
      {hasIngredients && (
        <div className="pt-4 border-t border-gray-100 dark:border-gray-800">
          <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-2 text-xs uppercase tracking-wide">
            {t(displayItem.itemType === 'drugstore' ? 'form.ingredients.inciList' : 'detail.ingredientsTitle')}
          </h4>
          <p className="text-gray-600 dark:text-gray-400 italic text-xs leading-relaxed bg-gray-50 dark:bg-gray-800/50 p-3 rounded-lg border border-gray-100 dark:border-gray-700/50">
              {displayItem.ingredients!.join(', ')}
          </p>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { FoodItem, NutriScore } from '../types';
import { StarIcon, TrashIcon, LactoseFreeIcon, VeganIcon, GlutenFreeIcon, ShoppingBagIcon, BuildingStorefrontIcon, UserGroupIcon, LockClosedIcon, ShoppingCartIcon, BeakerIcon } from './Icons';
import { useTranslation } from '../i18n/index';
import { useTranslatedItem } from '../hooks/useTranslatedItem';
import { StoreLogo } from './StoreLogo';
import { useAuth } from '../contexts/AuthContext';
import { triggerHaptic } from '../utils/haptics';

interface FoodItemCardProps {
  item: FoodItem;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  onViewDetails: (item: FoodItem) => void;
  onAddToShoppingList: (item: FoodItem) => void;
  onToggleFamilyStatus?: (item: FoodItem) => void;
  isPreview?: boolean;
  isInShoppingList?: boolean;
}

const nutriScoreColors: Record<NutriScore, string> = {
  A: 'bg-green-600',
  B: 'bg-lime-600',
  C: 'bg-yellow-500',
  D: 'bg-orange-500',
  E: 'bg-red-600',
};

const DietaryIcon: React.FC<{ type: 'lactoseFree' | 'vegan' | 'glutenFree', className?: string }> = ({ type, className }) => {
    const { t } = useTranslation();
    const icons = {
        lactoseFree: <LactoseFreeIcon className={`${className} text-blue-600 dark:text-blue-400`} />,
        vegan: <VeganIcon className={`${className}`} />,
        glutenFree: <GlutenFreeIcon className={`${className}`} />,
    };
    const tooltips = {
        lactoseFree: t('card.lactoseFreeTooltip'),
        vegan: t('card.veganTooltip'),
        glutenFree: t('card.glutenFreeTooltip'),
    };
    return (
        <div className="relative group flex items-center justify-center">
            {icons[type]}
            <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max px-2 py-1 bg-gray-800 text-white text-xs rounded-md opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-10">
                {tooltips[type]}
            </span>
        </div>
    );
}

// Internal component for the actual content
const FoodItemCardContent: React.FC<FoodItemCardProps> = ({ item, onDelete, onEdit, onViewDetails, onAddToShoppingList, onToggleFamilyStatus, isPreview = false, isInShoppingList = false }) => {
  const { t, language } = useTranslation();
  const { user } = useAuth();
  const displayItem = useTranslatedItem(item);

  // Swipe State
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchOffset, setTouchOffset] = useState(0);
  const SWIPE_THRESHOLD = 80;

  if (!displayItem) {
    return null;
  }

  const hasDietaryOrAllergens = displayItem.itemType === 'product' && (displayItem.isLactoseFree || displayItem.isVegan || displayItem.isGlutenFree || (displayItem.allergens && displayItem.allergens.length > 0));
  const hasTags = displayItem.tags && displayItem.tags.length > 0;
  // If not a preview, the card is clickable to Edit
  const isClickable = !isPreview;
  const isFamilyShared = displayItem.isFamilyFavorite;
  const isOwner = user?.id === displayItem.user_id;

  const getPlaceholderIcon = () => {
      switch(displayItem.itemType) {
          case 'dish': return <BuildingStorefrontIcon className="w-6 h-6 text-gray-400/50"/>;
          case 'drugstore': return <BeakerIcon className="w-6 h-6 text-gray-400/50"/>;
          default: return <ShoppingBagIcon className="w-6 h-6 text-gray-400/50"/>;
      }
  };

  const getStatusIcon = () => {
      switch(displayItem.itemType) {
          case 'dish': return <BuildingStorefrontIcon className="w-2.5 h-2.5" />;
          case 'drugstore': return <BeakerIcon className="w-2.5 h-2.5" />;
          default: return null;
      }
  };

  const statusIcon = getStatusIcon();

  let borderClass = 'border-gray-100 dark:border-gray-700';
  let ringClass = '';

  if (isFamilyShared) {
      borderClass = 'border-amber-200 dark:border-amber-800';
      ringClass = 'ring-1 ring-amber-100 dark:ring-amber-900/30';
  }

  // Swipe Handlers
  const onTouchStart = (e: React.TouchEvent) => {
      if (isPreview) return;
      setTouchStart(e.targetTouches[0].clientX);
  };

  const onTouchMove = (e: React.TouchEvent) => {
      if (touchStart === null || isPreview) return;
      const currentTouch = e.targetTouches[0].clientX;
      const diff = currentTouch - touchStart;
      if (diff < 0) {
          setTouchOffset(Math.max(diff, -150));
      }
  };

  const onTouchEnd = () => {
      if (touchStart === null || isPreview) return;
      if (touchOffset < -SWIPE_THRESHOLD) {
          triggerHaptic('warning');
          onDelete(item.id);
          setTouchOffset(0); 
      } else {
          setTouchOffset(0);
      }
      setTouchStart(null);
  };

  const handleCardClick = () => {
      if (Math.abs(touchOffset) > 5) return;

      if (isPreview) {
          // In preview mode (e.g. Discover or Duplicate check), show details modal if available
          if (onViewDetails) onViewDetails(item);
      } else {
          // In Dashboard, go straight to Edit Form
          onEdit(item.id);
      }
  };

  return (
    <div className={`relative h-24 sm:h-28 w-full select-none touch-pan-y rounded-xl ${isPreview ? '' : 'overflow-hidden'}`}>

        {/* Background Action Layer */}
        {!isPreview && (
            <div 
                className="absolute inset-0 bg-red-500 flex items-center justify-end pr-6 rounded-xl transition-opacity duration-200"
                style={{ opacity: Math.abs(touchOffset) > 20 ? 1 : 0 }}
            >
                <TrashIcon className="w-6 h-6 text-white" />
            </div>
        )}

        {/* Foreground Card */}
        <div 
            className={`group bg-white dark:bg-gray-800 rounded-xl shadow-sm border overflow-hidden transition-transform duration-200 relative flex flex-row h-full w-full ${isClickable ? 'cursor-pointer' : ''} ${borderClass} ${ringClass}`}
            style={{ transform: `translateX(${touchOffset}px)` }}
            onTouchStart={onTouchStart}
            onTouchMove={onTouchMove}
            onTouchEnd={onTouchEnd}
            onClick={handleCardClick}
        >
            {/* Left Side: Image */}
            <div className="relative aspect-square h-full shrink-0 bg-gray-50 dark:bg-gray-700/50 overflow-hidden">
                {displayItem.image ? (
                    <img 
                        src={displayItem.image} 
                        alt={displayItem.name} 
                        loading="lazy"
                        className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" 
                    />
                ) : (
                    <div className="w-full h-full flex items-center justify-center bg-gray-100 dark:bg-gray-700/50">
                        {getPlaceholderIcon()}
                    </div>
                )}

                {/* Top Left Status Overlay */}
                <div className="absolute top-1 left-1 flex flex-col gap-1">
                    {statusIcon && (
                        <div className="bg-white/90 dark:bg-black/60 backdrop-blur-md p-0.5 rounded-full text-gray-700 dark:text-gray-200 shadow-sm border border-black/5 dark:border-white/10">
                            {statusIcon}
                        </div>
                    )}

                    <button
                        type="button" 
                        className={`backdrop-blur-md p-0.5 rounded-full shadow-sm transition-all duration-200 border border-black/5 dark:border-white/10 ${isFamilyShared ? 'bg-amber-100/90 text-amber-700 dark:bg-amber-900/80 dark:text-amber-300' : 'bg-white/90 text-gray-400 dark:bg-black/60 dark:text-gray-400'} ${isOwner && !isPreview ? 'cursor-pointer hover:scale-110 active:scale-95' : ''}`}
                        onClick={(e) => {
                            if (isOwner && !isPreview && onToggleFamilyStatus) {
                                e.stopPropagation();
                                onToggleFamilyStatus(item);
                            }
                        }}
                        disabled={!isOwner || isPreview}
                    >
                        {isFamilyShared ? <UserGroupIcon className="w-2.5 h-2.5" /> : <LockClosedIcon className="w-2.5 h-2.5" />}
                    </button>
                </div>

                {/* NutriScore */}
                {displayItem.itemType === 'product' && displayItem.nutriScore && (
                    <div className={`absolute bottom-1 right-1 text-[9px] w-4 h-4 rounded-full text-white font-bold flex items-center justify-center shadow-sm border border-white/20 ${nutriScoreColors[displayItem.nutriScore]}`}>
                        {displayItem.nutriScore}
                    </div>
                )}
            </div>

            {/* Right Side: Content - Compact Layout */}
            <div className="flex-1 flex flex-col justify-between p-2 min-w-0 relative">

                <div>
                    <div className="flex justify-between items-start gap-1">
                        <h3 className="text-sm sm:text-base font-bold text-gray-900 dark:text-white truncate leading-tight tracking-tight" title={displayItem.name}>
                            {displayItem.name}
                        </h3>

                        {!isPreview && (
                            <div className="flex items-center gap-0.5 -mr-1 -mt-1 shrink-0">
                                {displayItem.itemType !== 'dish' && (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); onAddToShoppingList(item); }}
                                        className={`p-1 rounded-full transition-all duration-200 ${
                                            isInShoppingList 
                                            ? 'bg-indigo-600 text-white shadow-sm' 
                                            : 'text-gray-400 hover:bg-indigo-50 hover:text-indigo-600 dark:hover:bg-indigo-900/30 dark:hover:text-indigo-300'
                                        }`}
                                    >
                                        {isInShoppingList ? <ShoppingCartIcon className="w-3.5 h-3.5" /> : <ShoppingBagIcon className="w-3.5 h-3.5" />}
                                    </button>
                                )}
                            </div>
                        )}
                    </div>

                    <div className="flex items-center gap-0.5 mt-0.5">
                        {[1, 2, 3, 4, 5].map(star => (
                            <StarIcon key={star} className={`w-3 h-3 ${displayItem.rating >= star ? 'text-yellow-400 fill-current' : 'text-gray-200 dark:text-gray-700'}`} filled={displayItem.rating >= star} />
                        ))}
                    </div>

                    <div className="mt-1 min-h-[1rem] flex items-center justify-between">
                        <div className="overflow-hidden flex-1">
                            {displayItem.itemType === 'dish' && displayItem.restaurantName && (
                                <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate italic flex items-center gap-1">
                                    <BuildingStorefrontIcon className="w-2.5 h-2.5"/> {displayItem.restaurantName}
                                </p>
                            )}

                            {(displayItem.itemType === 'product' || displayItem.itemType === 'drugstore') && displayItem.purchaseLocation && displayItem.purchaseLocation.length > 0 && (
                                <div className="flex items-center gap-0.5 overflow-hidden">
                                    {displayItem.purchaseLocation.slice(0, 3).map((loc, idx) => (
                                        <StoreLogo key={idx} name={loc} size="sm" showName={false} className="w-3.5 h-3.5 opacity-80 grayscale-[0.3]" />
                                    ))}
                                    {displayItem.purchaseLocation.length > 3 && (
                                        <span className="text-[9px] text-gray-400">+{displayItem.purchaseLocation.length - 3}</span>
                                    )}
                                </div>
                            )}
                        </div>

                        {/* PRICE BADGE ON CARD */}
                        {typeof displayItem.price === 'number' && (
                            <span className="text-[10px] font-bold text-gray-700 dark:text-gray-300 bg-gray-100 dark:bg-gray-700/50 px-1.5 py-0.5 rounded ml-1 shrink-0 whitespace-nowrap">
                                {displayItem.price.toFixed(2)}€
                            </span>
                        )}
                    </div>
                </div>

                {/* Footer Row: Tags & Dietary Badges */}
