    }
    setItemToAdd(null);
    setPotentialDuplicates([]);
    handleCancelForm();
  }, [itemToAdd, saveItem, handleCancelForm]);

  const handleDeleteFormItem = useCallback(async (id: string) => {
      triggerHaptic('warning');
      if (window.confirm("Are you sure you want to delete this item?")) {
        await deleteItem(id);
      }
  }, [deleteItem]);


  const handleConversationalSearch = useCallback(async (query: string) => {
    setAiSearchQuery(query);
    setIsFilterPanelVisible(false);
    setAiSearchResults({ ids: null, error: null, isLoading: true });
    try {
      const resultIds = await geminiService.performConversationalSearch(query, foodItems);
      setAiSearchResults({ ids: resultIds, error: null, isLoading: false });
    } catch (e) {
      console.error(e);
      setAiSearchResults({ ids: null, error: t('conversationalSearch.error'), isLoading: false });
    }
  }, [foodItems, t]);

  const clearAiSearch = useCallback(() => {
    setAiSearchQuery('');
    setAiSearchResults({ ids: null, error: null, isLoading: false });
  }, []);

  const clearAllFilters = useCallback(() => {
    setSearchTerm('');
    setRatingFilter('all');
    setTypeFilter('all');
    setOwnerFilter('all');
    clearAiSearch();
  }, [clearAiSearch]);

  const handleToggleShoppingList = useCallback((item: FoodItem) => {
      const existingItem = shoppingListItems.find(i => i.food_item_id === item.id);

      if (existingItem) {
          removeItem(existingItem.id);
          triggerHaptic('medium');
          setToastMessage(t('shoppingList.removedToast', { name: item.name }));
      } else {
          addItemToList(item.id, 1);
          triggerHaptic('success');
          setToastMessage(t('shoppingList.addedToast', { name: item.name }));
      }
  }, [shoppingListItems, removeItem, addItemToList, t]);

  const handleSmartQuickAdd = useCallback(async (input: string) => {
      if (!user) return;
      setIsSmartAddLoading(true);
      try {
          const parsedItems = await geminiService.parseShoppingList(input);
          let addedCount = 0;
          const allAvailableItems = [...foodItems, ...familyFoodItems];

          for (const parsedItem of parsedItems) {
              let match = allAvailableItems.find(i => i.name.toLowerCase() === parsedItem.name.toLowerCase());
              let foodItemId = match?.id;

              if (!foodItemId) {
                  const newItemData: Omit<FoodItem, 'id' | 'user_id' | 'created_at'> = {
                      name: parsedItem.name,
                      rating: 0,
                      itemType: 'product', 
                      category: parsedItem.category,
                      isFamilyFavorite: !!userProfile?.household_id, 
                  };
                  try {
                      const { createFoodItem } = await import('./services/foodItemService');
                      const newItem = await createFoodItem(newItemData, user.id);
                      foodItemId = newItem.id;
                      refreshFoodData();
                  } catch (e) {
                      console.error("Failed to auto-create item", e);
                      continue;
                  }
              }

              if (foodItemId) {
                  addItemToList(foodItemId, parsedItem.quantity);
                  addedCount++;
              }
          }
          if (addedCount > 0) {
              triggerHaptic('success');
              setToastMessage(t('shoppingList.addedAnotherToast', { name: `${addedCount} items` }));
          }
      } catch (e) {
          console.error("Smart Add failed:", e);
          setToastMessage("Could not process list. Please try again.");
      } finally {
          setIsSmartAddLoading(false);
      }
  }, [user, foodItems, familyFoodItems, userProfile, addItemToList, refreshFoodData, t]);


  const handleHouseholdCreateWrapper = useCallback(async (name: string) => {
      try {
          await createHousehold(name);
          setToastMessage(t('shoppingList.joinSuccess', { householdName: name }));
      } catch (e) {
          // Error handled in hook
      }
  }, [createHousehold, t]);

  const handleAddSharedItem = useCallback(async () => {
    if (sharedItemToShow) {
      await saveItem(sharedItemToShow);
      triggerHaptic('success');
      setSharedItemToShow(null);
    }
  }, [sharedItemToShow, saveItem]);

  const handleViewDetails = useCallback((item: FoodItem) => {
    setDetailItem(item);
  }, []);

  const handleStartEdit = useCallback((id: string) => {
    const itemToEdit = [...foodItems, ...familyFoodItems].find(item => item.id === id);
    if (itemToEdit) {
      setDetailItem(null);
      setEditingItem(itemToEdit);
      setFormStartMode('none');
      setIsFormVisible(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [foodItems, familyFoodItems]);

  const handleQuickCamera = useCallback(() => {
      setEditingItem(null);
      setFormStartMode('camera');
      setIsFormVisible(true);
  }, []);

  const handleCancelDuplicateAdd = useCallback(() => {
    setItemToAdd(null);
    setPotentialDuplicates([]);
  }, []);

  const filteredAndSortedItems = useMemo(() => {
    const uniqueItemsMap = new Map<string, FoodItem>();
    familyFoodItems.forEach(item => uniqueItemsMap.set(item.id, item));
    foodItems.forEach(item => uniqueItemsMap.set(item.id, item));
    let items = Array.from(uniqueItemsMap.values());

    if (aiSearchResults.ids) {
      const idSet = new Set(aiSearchResults.ids);
      items = items.filter(item => idSet.has(item.id));
    }

    const lowerCaseSearchTerm = searchTerm.toLowerCase();

    items = items
      .filter(item => typeFilter === 'all' || item.itemType === typeFilter)
      .filter(item => {
        if (ownerFilter === 'mine') return item.user_id === user?.id; 
        if (ownerFilter === 'family') return item.isFamilyFavorite; 
        return true; 
      })
      .filter(item => {
        if (ratingFilter === 'all') return true;
        if (ratingFilter === 'liked') return item.rating >= 4;
        if (ratingFilter === 'disliked') return item.rating <= 2 && item.rating > 0;
        return true;
      })
      .filter(item =>  !searchTerm.trim() ? true : (
          item.name.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.notes?.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.tags?.join(' ').toLowerCase().includes(lowerCaseSearchTerm) ||
          (item.itemType === 'dish' && (
              item.restaurantName?.toLowerCase().includes(lowerCaseSearchTerm) ||
              item.cuisineType?.toLowerCase().includes(lowerCaseSearchTerm)
          ))
        )
      );

    return [...items].sort((a, b) => {
      switch (sortBy) {
        case 'date_asc': return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
        case 'rating_desc': return b.rating - a.rating;
        case 'rating_asc': return a.rating - b.rating;
        case 'name_asc': return a.name.localeCompare(b.name);
        case 'name_desc': return b.name.localeCompare(a.name);
        case 'date_desc':
        default: return new Date(b.created_at).getTime() - new Date(b.created_at).getTime();
      }
    });
  }, [foodItems, familyFoodItems, searchTerm, ratingFilter, typeFilter, ownerFilter, sortBy, aiSearchResults.ids, user?.id]);

  const toggleCategory = useCallback((category: string) => {
      setCollapsedCategories(prev => {
          const newSet = new Set(prev);
          if (newSet.has(category)) newSet.delete(category);
          else newSet.add(category);
          return newSet;
      });
  }, []);

  const allVisibleCategories = useMemo(() => {
      const cats = new Set<string>();
      filteredAndSortedItems.forEach(item => cats.add(item.category || 'other'));
      return Array.from(cats);
  }, [filteredAndSortedItems]);

  const isAllCollapsed = allVisibleCategories.length > 0 && collapsedCategories.size >= allVisibleCategories.length;

  const toggleAllCategories = useCallback(() => {
      if (isAllCollapsed) {
          setCollapsedCategories(new Set()); 
      } else {
          setCollapsedCategories(new Set(allVisibleCategories)); 
      }
  }, [isAllCollapsed, allVisibleCategories]);


  const hydratedShoppingList = useMemo((): HydratedShoppingListItem[] => {
      const allVisibleItems = [...foodItems, ...familyFoodItems];
      const foodItemMap = new Map(allVisibleItems.map(item => [item.id, item]));
      const hydratedItems: HydratedShoppingListItem[] = [];
      for (const sli of shoppingListItems) {
        const foodItemDetails = foodItemMap.get(sli.food_item_id);
        if (foodItemDetails) {
          hydratedItems.push(Object.assign({}, foodItemDetails, {
            shoppingListItemId: sli.id, checked: sli.checked, added_by_user_id: sli.added_by_user_id, checked_by_user_id: sli.checked_by_user_id, quantity: sli.quantity,
          }));
        }
      }
      return hydratedItems;
  }, [foodItems, familyFoodItems, shoppingListItems]);

  const handleToggleFamilyStatus = useCallback(async (item: FoodItem) => {
      if (!user || item.user_id !== user.id) return;
      const newStatus = !item.isFamilyFavorite;
      const { id, user_id, created_at, ...dataToSave } = item;
      const payload = { ...dataToSave, isFamilyFavorite: newStatus };
      const success = await saveItem(payload, id);
      if (success) {
          triggerHaptic('medium');
          setToastMessage(newStatus 
              ? t('toast.familyShared', { name: item.name }) 
              : t('toast.private', { name: item.name })
          );
      }
  }, [user, saveItem, t]);

  // --- Receipt Logic ---
  const handleReceiptCapture = async (imageDataUrl: string) => {
      setIsReceiptCameraOpen(false);
      setIsProcessingReceipt(true);
      try {
          // Optimization: Provide checked shopping list items as context hints for mapping
          const contextItems = hydratedShoppingList
              .filter(i => i.checked) // Prefer items that were recently bought
              .map(i => ({ id: i.id, name: i.name }));

          const analyzed = await geminiService.analyzeReceiptImage(imageDataUrl, contextItems);
          setScannedReceiptData(analyzed);
      } catch (e) {
          console.error("Receipt Analysis Failed", e);
          setToastMessage("Could not scan receipt.");
      } finally {
          setIsProcessingReceipt(false);
      }
  };

  const handleSaveReceipt = async (data: Partial<Receipt> & { items: Partial<ReceiptItem>[] }) => {
      if (!user) return;
      try {
          const savedReceipt = await createReceipt(data, user.id, userProfile?.household_id || undefined);
          setScannedReceiptData(null);
          refreshReceipts(); // Update dashboard

          if (savedReceipt && savedReceipt.items && savedReceipt.items.length > 0) {
              setConfirmedReceiptForImport({ 
                  receipt: savedReceipt as Receipt, 
                  items: savedReceipt.items as ReceiptItem[] 
              });
          } else {
              setToastMessage("Receipt Saved!");
          }
      } catch (e: any) {
          console.error("Save Receipt Failed", e);
          setToastMessage(`Failed to save receipt: ${e.message || 'Unknown error'}`);
      }
  };

  const handleImportReceiptItems = async (selectedItems: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[]) => {
      if (selectedItems.length > 0) {
          const success = await saveItemsBulk(selectedItems);
          if (success) {
              triggerHaptic('success');
              setToastMessage(`Imported ${selectedItems.length} items to inventory.`);
          } else {
              setToastMessage("Failed to import items.");
          }
      }
      setConfirmedReceiptForImport(null);
  };


  if (!session) {
    return <Auth />;
  }

  const renderContent = () => {
    // 1. Inventory View
    if (activeTab === 'inventory') {
        if (isFoodLoading && foodItems.length === 0) {
            return (
                <div className="flex flex-col items-center justify-center pt-20">
                    <SpinnerIcon className="w-12 h-12 text-indigo-500" />
                    <p className="mt-4 text-lg text-gray-600 dark:text-gray-400">Loading...</p>
                </div>
            );
        }

        // AI Search Banner Logic (only for Inventory)
        const aiBanner = aiSearchResults.ids !== null ? (
            <div className="mb-6 p-4 bg-indigo-50 dark:bg-gray-800 rounded-lg flex items-center justify-between border border-indigo-100 dark:border-indigo-900/50">
                <div>
                    <h2 className="text-xl font-bold text-indigo-800 dark:text-indigo-200">{t('conversationalSearch.resultsTitle')}</h2>
                    <p className="text-sm text-indigo-600 dark:text-indigo-300 italic">"{aiSearchQuery}"</p>
                </div>
                <button onClick={clearAiSearch} className="flex items-center gap-2 text-sm bg-indigo-200 dark:bg-indigo-600/50 hover:bg-indigo-300 dark:hover:bg-indigo-600/80 text-indigo-800 dark:text-indigo-100 font-semibold py-1.5 px-3 rounded-full transition">
                    <XMarkIcon className="w-4 h-4" />
                    {t('conversationalSearch.clear')}
                </button>
            </div>
        ) : null;

        const aiError = aiSearchResults.error ? <p className="text-red-500 dark:text-red-400 text-center my-4">{aiSearchResults.error}</p> : null;

        return (
            <>
                {aiBanner}
                {aiError}
                <Dashboard 
                    items={filteredAndSortedItems}
                    isLoading={isFoodLoading}
                    onAddNew={handleQuickCamera}
                    onEdit={handleStartEdit}
                    onDelete={handleDeleteFormItem}
                    onViewDetails={handleViewDetails}
                    onAddToShoppingList={handleToggleShoppingList}
                    onToggleFamilyStatus={handleToggleFamilyStatus}
                    shoppingListFoodIds={shoppingListFoodIds}
                    isFiltering={isAnyFilterActive}
                    collapsedCategories={collapsedCategories}
                    onToggleCategory={toggleCategory}
                />
            </>
        );
    } 

    // 2. Shopping List View
    else if (activeTab === 'shopping') {
        return (
            <ShoppingListView 
                allLists={shoppingLists}
                activeListId={activeShoppingListId}
                listData={hydratedShoppingList} 
                household={household}
                householdMembers={householdMembers}
                currentUser={user}
                onRemove={removeItem} 
                onClear={clearCompleted} 
                onToggleChecked={toggleChecked} 
                onSelectList={setActiveShoppingListId}
                onCreateList={createList}
                onDeleteList={deleteList}
                onUpdateQuantity={updateQuantity}
                onSmartAdd={handleSmartQuickAdd}
                isSmartAddLoading={isSmartAddLoading}
            />
        );
    }

    // 3. Finance View
    else if (activeTab === 'finance') {
        const monthlyData = getMonthlySpending();
        const categoryData = getCategoryBreakdown();
        const currentMonthLabel = new Date().toLocaleString('default', { month: 'short' });
        const currentTotal = monthlyData.find(d => d.label === currentMonthLabel)?.value || 0;

        return (
            <>
                <FinanceDashboard 
                    monthlyData={monthlyData}
                    categoryData={categoryData}
                    totalSpend={currentTotal}
                    isLoading={isReceiptsLoading}
                    onScan={() => setIsReceiptCameraOpen(true)}
                />

                {isReceiptCameraOpen && (
                    <CameraCapture 
                        onCapture={handleReceiptCapture}
                        onClose={() => setIsReceiptCameraOpen(false)}
                        mode="receipt"
                    />
                )}

                {isProcessingReceipt && (
                    <div className="fixed inset-0 bg-black/80 flex flex-col items-center justify-center z-50 animate-fade-in text-white">
                        <SpinnerIcon className="w-12 h-12 text-white mb-4" />
                        <p className="text-lg font-bold">Analyzing Receipt...</p>
                        <p className="text-sm opacity-70">Detecting items and matching to shopping list</p>
                    </div>
                )}

                {scannedReceiptData && (
                    <ReceiptReviewModal 
                        receiptData={scannedReceiptData}
                        onSave={handleSaveReceipt}
                        onClose={() => setScannedReceiptData(null)}
                    />
                )}

                {confirmedReceiptForImport && (
                    <ReceiptToInventoryModal 
                        receipt={confirmedReceiptForImport.receipt}
                        items={confirmedReceiptForImport.items}
                        onConfirm={handleImportReceiptItems}
                        onClose={() => setConfirmedReceiptForImport(null)}
                    />
                )}
            </>
        );
    }
  }

  const displayError = foodError || householdError || shoppingListError;

  return (
    <div className="min-h-[100dvh] bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans transition-colors duration-300">

       {isFormVisible && (
            <div className="fixed inset-0 z-50 overflow-y-auto bg-gray-100 dark:bg-gray-900 p-safe-top">
                <FoodItemForm 
                    onSaveItem={handleSaveFormItem} 
                    onCancel={handleCancelForm}
                    initialData={editingItem}
                    initialItemType={editingItem?.itemType || 'product'}
                    householdId={userProfile?.household_id || null}
                    startMode={formStartMode}
                />
            </div>
       )}

       {!isFormVisible && (
           <>
            <header className="bg-white/80 dark:bg-gray-800/50 backdrop-blur-sm shadow-md dark:shadow-lg sticky top-0 z-30 pt-safe-top">
                <div className="container mx-auto px-4 py-4">
                    <div className="flex justify-between items-center gap-4">
                        <h1 className="text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-green-500 dark:from-indigo-400 dark:to-green-400">
                            {t('header.title')}
                        </h1>
                        <button onClick={() => setIsSettingsOpen(true)} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors" aria-label={t('settings.title')}>
                            <SettingsIcon className="w-7 h-7 text-gray-600 dark:text-gray-300" />
                        </button>
                    </div>

                    {activeTab === 'inventory' && (
                        <div className="mt-4 space-y-3">
                            <div className="flex gap-2 items-center">
                            <div className="relative flex-1">
                                <input
                                    type="search"
                                    placeholder={t('header.searchPlaceholder')}
                                    value={searchTerm}
                                    onChange={e => setSearchTerm(e.target.value)}
                                    className="w-full bg-gray-200 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-full shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2 pl-10 pr-4 transition"
                                />
                                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                                    <MagnifyingGlassIcon className="w-5 h-5 text-gray-400 dark:text-gray-500" />
                                </div>
                            </div>

                            <div className="flex items-center gap-1 bg-gray-200 dark:bg-gray-700 rounded-md p-1">
                                <button 
                                    onClick={() => setIsFilterPanelVisible(true)} 
                                    className="flex items-center justify-center p-2 rounded-md hover:bg-white dark:hover:bg-gray-600 transition-colors text-gray-700 dark:text-gray-200"
                                    title={t('header.filter.button')}
                                >
                                    <FunnelIcon className="w-5 h-5" />
                                </button>

                                <div className="w-px h-6 bg-gray-300 dark:bg-gray-600 mx-0.5"></div>

                                <button
                                    onClick={toggleAllCategories}
                                    className="flex items-center justify-center p-2 rounded-md hover:bg-white dark:hover:bg-gray-600 transition-colors text-gray-700 dark:text-gray-200"
                                    title={isAllCollapsed ? "Alles ausklappen" : "Alles einklappen"}
                                >
                                    {isAllCollapsed ? <ArrowsPointingOutIcon className="w-5 h-5" /> : <ArrowsPointingInIcon className="w-5 h-5" />}
                                </button>
                            </div>
                            </div>

                            {isAnyFilterActive && (
                                <div className="flex items-center gap-2 flex-wrap pt-1">
                                    {ownerFilter !== 'all' && <ActiveFilterPill onDismiss={() => setOwnerFilter('all')}>{t(`header.filter.active.owner.${ownerFilter}`)}</ActiveFilterPill>}
                                    {searchTerm.trim() && <ActiveFilterPill onDismiss={() => setSearchTerm('')}>{t('header.filter.active.search', { term: searchTerm })}</ActiveFilterPill>}
                                    {aiSearchQuery && <ActiveFilterPill onDismiss={clearAiSearch}>{t('header.filter.active.aiSearch', { term: aiSearchQuery })}</ActiveFilterPill>}
                                    {typeFilter !== 'all' && <ActiveFilterPill onDismiss={() => setTypeFilter('all')}>{t(`header.filter.active.type.${typeFilter}`)}</ActiveFilterPill>}
                                    {ratingFilter !== 'all' && <ActiveFilterPill onDismiss={() => setRatingFilter('all')}>{t(`header.filter.active.rating.${ratingFilter}`)}</ActiveFilterPill>}
                                    <button onClick={clearAllFilters} className="text-xs text-indigo-600 dark:text-indigo-400 hover:underline">{t('header.filter.clearAll')}</button>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </header>

            <OfflineIndicator isOnline={isOnline} />

            <main className="container mx-auto p-4 md:p-8 pb-32">
                {displayError && isOnline && <div className="bg-red-100 dark:bg-red-900/50 border border-red-400 text-red-700 dark:text-red-300 px-4 py-3 rounded-lg relative mb-6" role="alert">{displayError}</div>}
                {renderContent()}
            </main>

            {activeTab === 'inventory' && (
                <div className="fixed bottom-[calc(5rem+env(safe-area-inset-bottom,0px))] right-6 z-30">
                    <button
                        onClick={handleQuickCamera}
                        className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold p-4 rounded-full shadow-xl transition-transform transform hover:scale-105 flex items-center justify-center active:scale-95"
                        aria-label={t('form.button.takePhoto')}
                    >
                        <CameraIcon className="w-8 h-8" />
                    </button>
                </div>
            )}

            <BottomNavigation 
                activeTab={activeTab} 
                onTabChange={setActiveTab} 
                shoppingListCount={shoppingListItems.filter(i => !i.checked).length}
            />
           </>
       )}

      {toastMessage && (
         <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-800 dark:bg-gray-200 text-white dark:text-gray-900 text-sm font-semibold py-2 px-4 rounded-full shadow-lg animate-fade-in-out z-50">
            {toastMessage}
        </div>
      )}

      {isFilterPanelVisible && (
        <FilterPanel 
            onClose={() => setIsFilterPanelVisible(false)}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            typeFilter={typeFilter}
            setTypeFilter={setTypeFilter}
            ratingFilter={ratingFilter}
            setRatingFilter={setRatingFilter}
            ownerFilter={ownerFilter}
            setOwnerFilter={setOwnerFilter}
            sortBy={sortBy}
            setSortBy={setSortBy}
            onReset={clearAllFilters}
            onAiSearch={handleConversationalSearch}
            isAiSearchLoading={aiSearchResults.isLoading}
        />
      )}

      {isSettingsOpen && <SettingsModal 
          onClose={() => setIsSettingsOpen(false)} 
          household={household}
          householdMembers={householdMembers}
          onHouseholdCreate={handleHouseholdCreateWrapper}
          onHouseholdLeave={leaveHousehold}
          onHouseholdDelete={deleteHousehold}
          error={householdError} 
      />}

      {potentialDuplicates.length > 0 && itemToAdd && (
        <DuplicateConfirmationModal items={potentialDuplicates} itemName={itemToAdd.name} onConfirm={handleConfirmDuplicateAdd} onCancel={handleCancelDuplicateAdd} />
      )}

      {detailItem && <FoodItemDetailModal 
        item={detailItem}
        currentUser={user}
        onClose={() => setDetailItem(null)}
        onEdit={() => handleStartEdit(detailItem.id)}
        onImageClick={setSelectedImage}
      />}

      {sharedItemToShow && (
        <div className="fixed inset-0 bg-black bg-opacity-70 flex items-center justify-center z-50 p-4 animate-fade-in" onClick={() => setSharedItemToShow(null)} role="dialog" aria-modal="true">
            <div className="relative bg-white dark:bg-gray-900 p-6 rounded-lg shadow-2xl max-w-lg w-full flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">{t('modal.shared.title')}</h2>
                <p className="text-gray-600 dark:text-gray-400 mb-4">{t('modal.shared.description')}</p>
                <div className="border border-gray-200 dark:border-gray-700 rounded-lg p-4 flex-1 overflow-y-auto">
                    <FoodItemDetailView item={{ ...sharedItemToShow, id: 'shared-item-preview', user_id: '', created_at: new Date().toISOString() }} onImageClick={setSelectedImage} />
                </div>
                <div className="mt-6 flex flex-col sm:flex-row justify-end gap-4 border-t border-gray-200 dark:border-gray-700 pt-6">
                <button onClick={() => setSharedItemToShow(null)} className="w-full sm:w-auto px-6 py-2 bg-gray-500 hover:bg-gray-600 dark:bg-gray-600 dark:hover:bg-gray-700 text-white rounded-md font-semibold transition-colors">{t('modal.shared.close')}</button>
                <button onClick={handleAddSharedItem} className="w-full sm:w-auto px-8 py-2 bg-indigo-600 text-white rounded-md font-semibold hover:bg-indigo-700 transition-colors">{t('modal.shared.addToList')}</button>
                </div>
            </div>
        </div>
      )}

      {selectedImage && <ImageModal imageUrl={selectedImage} onClose={() => setSelectedImage(null)} />}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useTranslation } from '../../i18n/index';
import { Receipt, ReceiptItem, FoodItem, GroceryCategory } from '../../types';
import { XMarkIcon, CheckCircleIcon, PlusCircleIcon, CategoryOtherIcon, CategoryProduceIcon, CategoryBakeryIcon, CategoryMeatIcon, CategoryDairyIcon, CategoryPantryIcon, CategoryFrozenIcon, CategorySnacksIcon, CategoryBeveragesIcon, CategoryHouseholdIcon, CategoryPersonalCareIcon, CategoryRestaurantIcon, CheckBadgeIcon } from '../Icons';

interface ReceiptToInventoryModalProps {
    receipt: Receipt;
    items: ReceiptItem[];
    onConfirm: (selectedItems: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[]) => Promise<void>;
    onClose: () => void;
}

const CategoryIconMap: Record<GroceryCategory, React.FC<{ className?: string }>> = {
    'produce': CategoryProduceIcon,
    'bakery': CategoryBakeryIcon,
    'meat_fish': CategoryMeatIcon,
    'dairy_eggs': CategoryDairyIcon,
    'pantry': CategoryPantryIcon,
    'frozen': CategoryFrozenIcon,
    'snacks': CategorySnacksIcon,
    'beverages': CategoryBeveragesIcon,
    'household': CategoryHouseholdIcon,
    'personal_care': CategoryPersonalCareIcon,
    'restaurant_food': CategoryRestaurantIcon,
    'other': CategoryOtherIcon,
};

export const ReceiptToInventoryModal: React.FC<ReceiptToInventoryModalProps> = ({ receipt, items, onConfirm, onClose }) => {
    const { t } = useTranslation();
    const [selectedIndices, setSelectedIndices] = useState<Set<number>>(new Set());
    const [isSaving, setIsSaving] = useState(false);

    // Initial Selection Logic
    useEffect(() => {
        const initialSelection = new Set<number>();
        items.forEach((item, index) => {
            // Priority 1: Match from Shopping List (Entity already exists)
            // Priority 2: Exclude household/personal_care by default for inventory import
            if (item.food_item_id) {
                // If it's already matched, we don't NEED to import it as a new item,
                // but we might want to check it if the user wants to "refresh" it.
                // USUALLY: Match means it's tracked. New price is saved to history automatically by DB trigger or service.
            } else if (item.category !== 'household' && item.category !== 'personal_care') {
                initialSelection.add(index);
            }
        });
        setSelectedIndices(initialSelection);
    }, [items]);

    const toggleItem = (index: number) => {
        setSelectedIndices(prev => {
            const next = new Set(prev);
            if (next.has(index)) next.delete(index);
            else next.add(index);
            return next;
        });
    };

    const toggleAll = () => {
        if (selectedIndices.size === items.length) {
            setSelectedIndices(new Set());
        } else {
            setSelectedIndices(new Set(items.map((_, i) => i)));
        }
    };

    const handleImport = async () => {
        setIsSaving(true);
        const foodItemsToCreate: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[] = [];

        selectedIndices.forEach(index => {
            const rItem = items[index];
            foodItemsToCreate.push({
                name: rItem.raw_name,
                rating: 0,
                itemType: 'product',
                category: rItem.category,
                purchaseLocation: [receipt.merchant_name],
                isFamilyFavorite: false,
                price: rItem.price
            });
        });

        await onConfirm(foodItemsToCreate);
        setIsSaving(false);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50 p-0 sm:p-4 animate-fade-in">
            <div className="bg-white dark:bg-gray-900 w-full h-full sm:h-[90vh] sm:max-w-2xl sm:rounded-xl shadow-2xl flex flex-col overflow-hidden">
                <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 pt-safe-top flex justify-between items-center">
                    <div>
                        <h2 className="text-lg font-bold text-gray-900 dark:text-white">{t('modal.import.title')}</h2>
                        <p className="text-xs text-gray-500 dark:text-gray-400">{t('modal.import.description')}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-full text-gray-500">
                        <XMarkIcon className="w-6 h-6" />
                    </button>
                </div>

                <div className="flex justify-between items-center px-4 py-2 bg-white dark:bg-gray-900 border-b border-gray-100 dark:border-gray-800">
                    <button onClick={toggleAll} className="text-sm font-semibold text-indigo-600 dark:text-indigo-400">
                        {selectedIndices.size === items.length ? t('modal.import.deselectAll') : t('modal.import.selectAll')}
                    </button>
                    <span className="text-xs text-gray-400 font-mono">
                        {selectedIndices.size} / {items.length}
                    </span>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-2">
                    {items.map((item, idx) => {
                        const isSelected = selectedIndices.has(idx);
                        const isAlreadyMatched = !!item.food_item_id;
                        const CatIcon = CategoryIconMap[item.category || 'other'];

                        return (
                            <div 
                                key={idx} 
                                onClick={() => !isAlreadyMatched && toggleItem(idx)}
                                className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${isAlreadyMatched ? 'bg-green-50 dark:bg-green-900/10 border-green-200 dark:border-green-800/50 opacity-80 cursor-default' : isSelected ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 cursor-pointer' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 opacity-60 cursor-pointer'}`}
                            >
                                <div className={`w-5 h-5 rounded-full border flex items-center justify-center flex-shrink-0 transition-colors ${isAlreadyMatched ? 'bg-green-500 border-green-500' : isSelected ? 'bg-indigo-600 border-indigo-600' : 'border-gray-400 bg-transparent'}`}>
                                    {(isAlreadyMatched || isSelected) && <CheckCircleIcon className="w-4 h-4 text-white" />}
                                </div>

                                <div className="flex-1 min-w-0">
                                    <p className={`text-sm font-bold truncate ${isSelected || isAlreadyMatched ? 'text-gray-900 dark:text-white' : 'text-gray-500 dark:text-gray-400'}`}>
                                        {item.raw_name}
                                    </p>
                                    <div className="flex items-center gap-2 mt-0.5">
                                        <div className="flex items-center gap-1 text-xs text-gray-500 dark:text-gray-400">
                                            <CatIcon className="w-3 h-3" />
                                            <span>{t(`category.${item.category}`)}</span>
                                        </div>
                                        {isAlreadyMatched && (
                                            <span className="flex items-center gap-1 text-[10px] bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-300 px-1.5 py-0.5 rounded-full font-bold uppercase tracking-wider">
                                                <CheckBadgeIcon className="w-3 h-3" /> Verknüpft
                                            </span>
                                        )}
                                    </div>
                                </div>

                                <div className="text-right">
                                    <span className="block text-sm font-mono text-gray-600 dark:text-gray-300">
                                        {item.price.toFixed(2)}€
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>

                <div className="p-4 border-t border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 pb-safe-bottom flex gap-3">
                    <button 
                        onClick={onClose} 
                        className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-300 font-bold rounded-xl transition-colors"
                    >
                        {t('modal.import.button.skip')}
                    </button>
                    <button 
                        onClick={handleImport}
                        disabled={(selectedIndices.size === 0 && !items.some(i => i.food_item_id)) || isSaving}
                        className="flex-[2] py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-md transition-transform active:scale-95 disabled:bg-indigo-400 flex items-center justify-center gap-2"
                    >
                        {isSaving ? "Importing..." : t('modal.import.button.add', { count: selectedIndices.size })}
                    </button>
                </div>
            </div>
        </div>
    );
};

import { supabase } from './supabaseClient';
import { FoodItem, NutriScore, FoodItemType, GroceryCategory } from '../types';

// Define the exact shape of the database table to ensure type safety
interface FoodItemDbPayload {
  user_id: string;
  name: string;
  rating: number;
  notes?: string;
  image_url?: string;
  tags?: string[];
  item_type: FoodItemType;
  category?: GroceryCategory;
  is_family_favorite: boolean;
  nutri_score?: NutriScore | null;
  calories?: number | null;
  ingredients?: string[];
  allergens?: string[];
  is_lactose_free: boolean;
  is_vegan: boolean;
  is_gluten_free: boolean;
  purchase_location?: string[];
  restaurant_name?: string;
  cuisine_type?: string;
  price?: number;
}

// --- Mappers ---

export const mapDbToFoodItem = (dbItem: any): FoodItem => {
  let locations: string[] = [];
  if (Array.isArray(dbItem.purchase_location)) {
    locations = dbItem.purchase_location;
  } else if (typeof dbItem.purchase_location === 'string' && dbItem.purchase_location.trim() !== '') {
    let raw = dbItem.purchase_location;
    if (raw.startsWith('[') && raw.endsWith(']')) {
      try {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) locations = parsed.map(String);
      } catch (e) {}
    }
    if (locations.length === 0) {
        if (raw.startsWith('{') && raw.endsWith('}')) raw = raw.slice(1, -1);
        locations = raw.split(',').map((l: string) => l.trim()).filter(Boolean);
    }
  }

  return {
    id: dbItem.id,
    user_id: dbItem.user_id,
    created_at: dbItem.created_at,
    name: dbItem.name,
    rating: dbItem.rating,
    notes: dbItem.notes,
    image: dbItem.image_url,
    tags: dbItem.tags,
    itemType: dbItem.item_type,
    category: dbItem.category || 'other',
    isFamilyFavorite: dbItem.is_family_favorite,
    nutriScore: dbItem.nutri_score,
    calories: dbItem.calories,
    ingredients: dbItem.ingredients,
    allergens: dbItem.allergens,
    isLactoseFree: dbItem.is_lactose_free,
    isVegan: dbItem.is_vegan,
    isGlutenFree: dbItem.is_gluten_free,
    purchaseLocation: locations,
    restaurantName: dbItem.restaurant_name,
    cuisineType: dbItem.cuisine_type,
    price: dbItem.price,
  } as FoodItem;
};

export const mapFoodItemToDbPayload = (item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'> & { user_id: string, image_url?: string }): FoodItemDbPayload => {
  return {
    user_id: item.user_id,
    name: item.name,
    rating: item.rating,
    notes: item.notes,
    image_url: item.image_url || item.image,
    tags: item.tags,
    item_type: item.itemType,
    category: item.category || 'other',
    is_family_favorite: item.isFamilyFavorite || false,
    nutri_score: item.nutriScore || null,
    calories: item.calories || null,
    ingredients: item.ingredients,
    allergens: item.allergens,
    is_lactose_free: item.isLactoseFree || false,
    is_vegan: item.isVegan || false,
    is_gluten_free: item.isGlutenFree || false,
    purchase_location: item.purchaseLocation,
    restaurant_name: item.restaurantName,
    cuisine_type: item.cuisineType,
    price: item.price,
  };
};

// --- API Operations ---

export const fetchUserFoodItems = async (userId: string) => {
  const { data, error } = await supabase
    .from('food_items')
    .select('*')
    .eq('user_id', userId)
    .order('created_at', { ascending: false });

  if (error) throw error;
  return (data || []).map(mapDbToFoodItem);
};

export const fetchFamilyFavorites = async () => {
    const { data, error } = await supabase
        .from('food_items')
        .select('*')
        .eq('is_family_favorite', true);

    if (error) throw error;
    return (data || []).map(mapDbToFoodItem);
};

export const createFoodItem = async (item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>, userId: string, imageUrl?: string) => {
  const payload = mapFoodItemToDbPayload({ ...item, user_id: userId, image_url: imageUrl });

  const { data, error } = await supabase
    .from('food_items')
    .insert(payload)
    .select()
    .single();

  if (error) {
      console.warn("Cascade retry for single item:", error.message);
      const { calories, ...payloadNoCalories } = payload;
      const { data: r1, error: e1 } = await supabase.from('food_items').insert(payloadNoCalories).select().single();
      if (!e1) return mapDbToFoodItem(r1);

      const { category, ...payloadLegacy } = payloadNoCalories;
      const { data: r2, error: e2 } = await supabase.from('food_items').insert(payloadLegacy).select().single();
      if (!e2) return mapDbToFoodItem(r2);
      throw error;
  }
  return mapDbToFoodItem(data);
};

/**
 * Enhanced Bulk Import with Multi-Stage Recovery Strategy
 */
export const createFoodItemsBulk = async (items: (Omit<FoodItem, 'id' | 'user_id' | 'created_at'>)[], userId: string): Promise<FoodItem[]> => {
    if (items.length === 0) return [];

    const basePayloads = items.map(item => mapFoodItemToDbPayload({ ...item, user_id: userId }));

    // Helper for batch attempts
    const attemptBatch = async (payloads: any[]) => {
        const { data, error } = await supabase.from('food_items').insert(payloads).select();
        return { data, error };
    };

    // Stage 1: Full Batch
    let result = await attemptBatch(basePayloads);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    console.warn("Bulk import Stage 1 failed, trying without 'calories'...", result.error.message);

    // Stage 2: Remove 'calories'
    const payloadsNoCalories = basePayloads.map(({ calories, ...rest }) => rest);
    result = await attemptBatch(payloadsNoCalories);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    console.warn("Bulk import Stage 2 failed, trying without 'category'...", result.error.message);

    // Stage 3: Remove 'calories' AND 'category'
    const payloadsLegacy = payloadsNoCalories.map(({ category, ...rest }) => rest);
    result = await attemptBatch(payloadsLegacy);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    // Stage 4: Nuclear Option - Individual Inserts (Slow but guaranteed to save what's possible)
    console.warn("Bulk import Stage 3 failed. Switching to individual resilient inserts...");
    const savedItems: FoodItem[] = [];
    for (const item of items) {
        try {
            const saved = await createFoodItem(item, userId);
            savedItems.push(saved);
        } catch (e) {
            console.error("Failed to save individual item during bulk fallback:", item.name, e);
        }
    }

    if (savedItems.length === 0) throw new Error("Mass import failed completely. Check database connection and schema.");
    return savedItems;
};

export const updateFoodItem = async (id: string, item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>, userId: string, imageUrl?: string) => {
  const payload = mapFoodItemToDbPayload({ ...item, user_id: userId, image_url: imageUrl });

  const { data, error } = await supabase.from('food_items').update(payload).eq('id', id).select().single();

  if (error) {
      console.warn("Cascade retry for update:", error.message);
      const { calories, ...p1 } = payload;
      const { data: r1, error: e1 } = await supabase.from('food_items').update(p1).eq('id', id).select().single();
      if (!e1) return mapDbToFoodItem(r1);

      const { category, ...p2 } = p1;
      const { data: r2, error: e2 } = await supabase.from('food_items').update(p2).eq('id', id).select().single();
      if (!e2) return mapDbToFoodItem(r2);
      throw error;
  }
  return mapDbToFoodItem(data);
};

export const deleteFoodItem = async (id: string) => {
  const { error } = await supabase.from('food_items').delete().eq('id', id);
  if (error) throw error;
};

import { useState, useEffect, useCallback } from 'react';
import { FoodItem } from '../types';
import { User } from '@supabase/supabase-js';
import * as foodItemService from '../services/foodItemService';
import { supabase } from '../services/supabaseClient';

const base64ToBlob = (base64: string, mimeType: string): Blob => {
  const byteCharacters = atob(base64.split(',')[1]);
  const byteArrays = [];
  for (let offset = 0; offset < byteCharacters.length; offset += 512) {
    const slice = byteCharacters.slice(offset, offset + 512);
    const byteNumbers = new Array(slice.length);
    for (let i = 0; i < slice.length; i++) { byteNumbers[i] = slice.charCodeAt(i); }
    const byteArray = new Uint8Array(byteNumbers);
    byteArrays.push(byteArray);
  }
  return new Blob(byteArrays, { type: mimeType });
};

export const useFoodData = (user: User | null, householdId?: string | null) => {
  const [foodItems, setFoodItems] = useState<FoodItem[]>([]);
  const [familyFoodItems, setFamilyFoodItems] = useState<FoodItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchPersonalData = useCallback(async () => {
    if (!user) return;
    try {
      const items = await foodItemService.fetchUserFoodItems(user.id);
      setFoodItems(items);
    } catch (err: any) {
      console.error("Personal data fetch error:", err);
      setError(`Error loading personal data: ${err.message}`);
    }
  }, [user]);

  const fetchFamilyData = useCallback(async () => {
    if (!householdId) {
      setFamilyFoodItems([]);
      return;
    }
    try {
      const items = await foodItemService.fetchFamilyFavorites();
      setFamilyFoodItems(items);
    } catch (err: any) {
      console.error("Family data fetch error:", err);
    }
  }, [householdId]);

  useEffect(() => {
    let mounted = true;
    const load = async () => {
      setIsLoading(true);
      setError(null);
      await Promise.all([fetchPersonalData(), fetchFamilyData()]);
      if (mounted) setIsLoading(false);
    };

    if (user) {
      load();
    } else {
      setFoodItems([]);
      setFamilyFoodItems([]);
      setIsLoading(false);
    }

    return () => { mounted = false; };
  }, [user, householdId, fetchPersonalData, fetchFamilyData]);

  const saveItem = useCallback(async (
    itemData: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>,
    existingId?: string
  ): Promise<boolean> => {
    if (!user) {
      setError("You must be logged in to save items.");
      return false;
    }

    setError(null);
    let imageUrl = itemData.image;
    const originalItems = [...foodItems];
    const tempId = existingId || `temp_${Date.now()}`;

    const optimisticItem: FoodItem = {
      ...itemData,
      id: tempId,
      user_id: user.id,
      created_at: new Date().toISOString(),
      image: imageUrl || undefined,
      tags: itemData.tags || [],
    };

    if (existingId) {
      setFoodItems(prev => prev.map(item => item.id === existingId ? optimisticItem : item));
    } else {
      setFoodItems(prev => [optimisticItem, ...prev]);
    }

    if (imageUrl && imageUrl.startsWith('data:image')) {
      try {
        const mimeType = imageUrl.match(/data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+).*,.*/)?.[1] || 'image/jpeg';
        const blob = base64ToBlob(imageUrl, mimeType);
        const fileName = `${user.id}/${Date.now()}_${Math.random().toString(36).substring(2, 9)}.jpg`;
        const { error: uploadError } = await supabase.storage.from('food-images').upload(fileName, blob, { contentType: mimeType });
        if (uploadError) throw uploadError;
        const { data: urlData } = supabase.storage.from('food-images').getPublicUrl(fileName);
        imageUrl = urlData.publicUrl;
      } catch (uploadErr: any) {
        console.error("Upload error:", uploadErr);
        setError(`Failed to upload image: ${uploadErr.message}`);
        setFoodItems(originalItems);
        return false;
      }
    }

    try {
      let savedItem: FoodItem;
      if (existingId) {
        savedItem = await foodItemService.updateFoodItem(existingId, itemData, user.id, imageUrl);
        setFoodItems(prev => prev.map(item => item.id === savedItem.id ? savedItem : item));
      } else {
        savedItem = await foodItemService.createFoodItem(itemData, user.id, imageUrl);
        setFoodItems(prev => prev.map(item => item.id === tempId ? savedItem : item));
      }
      if (itemData.isFamilyFavorite && householdId) fetchFamilyData();
      return true;
    } catch (dbErr: any) {
      console.error("Database save error:", dbErr);
      setError(`Failed to save item: ${dbErr.message}`);
      setFoodItems(originalItems);
      return false;
    }
  }, [user, foodItems, householdId, fetchFamilyData]);

  const saveItemsBulk = useCallback(async (
      itemsData: (Omit<FoodItem, 'id' | 'user_id' | 'created_at'>)[]
  ): Promise<boolean> => {
      if (!user || itemsData.length === 0) return false;
      try {
          const savedItems = await foodItemService.createFoodItemsBulk(itemsData, user.id);
          if (savedItems.length > 0) {
              setFoodItems(prev => [...savedItems, ...prev]);
              if(householdId) fetchFamilyData();
              return true;
          }
          return false;
      } catch (e: any) {
          console.error("Bulk save error:", e);
          setError(`Failed to bulk save: ${e.message}`);
          return false;
      }
  }, [user, householdId, fetchFamilyData]);

  const deleteItem = useCallback(async (id: string) => {
    const originalItems = [...foodItems];
    setFoodItems(prev => prev.filter(item => item.id !== id));
    setError(null);
    try {
      await foodItemService.deleteFoodItem(id);
      if (householdId) fetchFamilyData();
    } catch (err: any) {
      console.error("Delete error:", err);
      setError(`Failed to delete item: ${err.message}`);
      setFoodItems(originalItems);
    }
  }, [foodItems, householdId, fetchFamilyData]);

  return {
    foodItems,
    familyFoodItems,
    isLoading,
    error,
    saveItem,
    saveItemsBulk,
    deleteItem,
    refreshData: fetchPersonalData
  };
};

import React, { useState, useEffect } from 'react';
import { useTranslation } from '../../i18n/index';
import { Receipt, ReceiptItem, FoodItem, GroceryCategory } from '../../types';
import { XMarkIcon, CheckCircleIcon, PlusCircleIcon, CategoryOtherIcon, CategoryProduceIcon, CategoryBakeryIcon, CategoryMeatIcon, CategoryDairyIcon, CategoryPantryIcon, CategoryFrozenIcon, CategorySnacksIcon, CategoryBeveragesIcon, CategoryHouseholdIcon, CategoryPersonalCareIcon, CategoryRestaurantIcon, CheckBadgeIcon, SpinnerIcon } from '../Icons';

interface ReceiptToInventoryModalProps {
    receipt: Receipt;
    items: ReceiptItem[];
    onConfirm: (selectedItems: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[]) => Promise<void>;
    onClose: () => void;
}

const CategoryIconMap: Record<GroceryCategory, React.FC<{ className?: string }>> = {
    'produce': CategoryProduceIcon,
    'bakery': CategoryBakeryIcon,
    'meat_fish': CategoryMeatIcon,
    'dairy_eggs': CategoryDairyIcon,
    'pantry': CategoryPantryIcon,
    'frozen': CategoryFrozenIcon,
    'snacks': CategorySnacksIcon,
    'beverages': CategoryBeveragesIcon,
    'household': CategoryHouseholdIcon,
    'personal_care': CategoryPersonalCareIcon,
    'restaurant_food': CategoryRestaurantIcon,
    'other': CategoryOtherIcon,
};

export const ReceiptToInventoryModal: React.FC<ReceiptToInventoryModalProps> = ({ receipt, items, onConfirm, onClose }) => {
    const { t } = useTranslation();
    const [selectedIndices, setSelectedIndices] = useState<Set<number>>(new Set());
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const initialSelection = new Set<number>();
        items.forEach((item, index) => {
            if (item.food_item_id) {
                // Skip already matched
            } else if (item.category !== 'household' && item.category !== 'personal_care') {
                initialSelection.add(index);
            }
        });
        setSelectedIndices(initialSelection);
    }, [items]);

    const toggleItem = (index: number) => {
        setSelectedIndices(prev => {
            const next = new Set(prev);
            if (next.has(index)) next.delete(index);
            else next.add(index);
            return next;
        });
    };

    const toggleAll = () => {
        if (selectedIndices.size === items.length) {
            setSelectedIndices(new Set());
        } else {
            setSelectedIndices(new Set(items.map((_, i) => i)));
        }
    };

    const handleImport = async () => {
        if (selectedIndices.size === 0) {
            onClose();
            return;
        }

        setIsSaving(true);
        setError(null);

        try {
            const foodItemsToCreate: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[] = [];
            selectedIndices.forEach(index => {
                const rItem = items[index];
                foodItemsToCreate.push({
                    name: rItem.raw_name,
                    rating: 0,
