};

// Helper to calculate Grundpreis (e.g. price per 100g or 1kg)
const calculateNormalizedPrice = (price: number, quantity: number, unit: UnitType): { value: number, label: string } | null => {
    if (!price || !quantity || !unit) return null;

    let normalizedValue = 0;
    let label = '';

    switch(unit) {
        case 'g':
            normalizedValue = (price / quantity) * 100;
            label = '100g';
            break;
        case 'ml':
            normalizedValue = (price / quantity) * 100;
            label = '100ml';
            break;
        case 'kg':
        case 'l':
            normalizedValue = price / quantity;
            label = `1${unit}`;
            break;
        case 'stk':
            normalizedValue = price / quantity;
            label = 'Stück';
            break;
        default:
            return null;
    }

    return { value: normalizedValue, label };
};

