// Add missing BoundingBox interface
export interface BoundingBox {
    x: number;
    y: number;
    width: number;
    height: number;
}

export const hasValidApiKey = (): boolean => {
    return !!process.env.API_KEY;
};

export function getAiClient() {
    if (!process.env.API_KEY) {
        throw new Error("API key not found. Please ensure it's set in your environment variables.");
    }
    return ai;
}

const resizeImage = (base64Str: string, mode: 'main' | 'text' | 'receipt' = 'main'): Promise<string> => {
    let maxWidth = 1024;
    let quality = 0.85;
    if (mode === 'text') maxWidth = 1200;
    else if (mode === 'receipt') maxWidth = 1536;

    return new Promise((resolve) => {
        const img = new Image();
        img.src = base64Str;
        img.onload = () => {
            let width = img.width;
            let height = img.height;
            if (width > maxWidth) {
                height = Math.round((height * maxWidth) / width);
                width = maxWidth;
            }
            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', quality));
            } else resolve(base64Str);
        };
        img.onerror = () => resolve(base64Str);
    });
};

const parseJsonFromString = (text: string) => {
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch && jsonMatch[1]) return JSON.parse(jsonMatch[1]);
    try { return JSON.parse(text); } catch (e) {
        const arrayMatch = text.match(/(\[[\s\S]*\])/);
        if (arrayMatch && arrayMatch[1]) { try { return JSON.parse(arrayMatch[1]); } catch (p) {} }
    }
    throw new Error("Could not parse JSON from AI response.");
};

// Add missing analyzeFoodImage function
export const analyzeFoodImage = async (base64Image: string): Promise<{
    name?: string;
    tags?: string[];
    nutriScore?: string;
    category?: GroceryCategory;
    itemType?: FoodItemType;
    boundingBox?: BoundingBox;
    image?: string;
}> => {
    const resizedImage = await resizeImage(base64Image, 'main');
    const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
    if (!match) throw new Error("Invalid base64 image string.");
    const mimeType = match[1];
    const data = match[2];

    const gemini = getAiClient();
    const response = await gemini.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
            parts: [
                { inlineData: { mimeType, data } },
                { text: "Identify the product name, descriptive tags, Nutri-Score, category, and whether it is a product, dish, or drugstore item. Also return a bounding box [ymin, xmin, ymax, xmax] normalized to 1000 for the subject." }
            ]
        },
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING },
                    tags: { type: Type.ARRAY, items: { type: Type.STRING } },
                    nutriScore: { type: Type.STRING },
                    category: { type: Type.STRING, enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'] },
                    itemType: { type: Type.STRING, enum: ['product', 'dish', 'drugstore'] },
                    boundingBox: { type: Type.ARRAY, items: { type: Type.NUMBER } }
                }
            }
        }
    });

    const result = JSON.parse(response.text || '{}');
    let bbox: BoundingBox | undefined;
    if (result.boundingBox && result.boundingBox.length === 4) {
        const [ymin, xmin, ymax, xmax] = result.boundingBox;
        bbox = { x: xmin / 10, y: ymin / 10, width: (xmax - xmin) / 10, height: (ymax - ymin) / 10 };
    }

    return { ...result, boundingBox: bbox, image: resizedImage };
};

