    const [newShop, setNewShop] = useState('');

    const handleAdd = () => {
        if(newShop.trim()) {
            addSavedShop(newShop);
            setNewShop('');
        }
    };

    return (
        <div>
            <h3 className="text-lg font-semibold text-gray-800 dark:text-gray-200 mb-3">{t('settings.shops.title')}</h3>
