    return (
        <FoodItemForm 
            onSaveItem={handleSave}
            onCancel={() => navigate(-1)}
            initialData={initialItem}
            initialItemType={initialItem?.itemType || 'product'}
            householdId={householdId}
            startMode={startMode}
        />
