// --- MAIN APP COMPONENT ---

export const App: React.FC = () => {
  const { t } = useTranslation();
  const { session, user } = useAuth();
  const navigate = useNavigate();

  // --- Hook Integration ---

  const { 
    userProfile, household, householdMembers, 
    loading: isHouseholdLoading, error: householdError,
    createHousehold, joinHousehold, leaveHousehold, deleteHousehold, refreshHousehold
  } = useHousehold(user);

  const { 
    foodItems, familyFoodItems, isLoading: isFoodLoading, error: foodError, 
    saveItem, saveItemsBulk, deleteItem, refreshData: refreshFoodData
  } = useFoodData(user, userProfile?.household_id);

  const {
    shoppingLists, activeShoppingListId, shoppingListItems, error: shoppingListError,
    setActiveShoppingListId, createList, deleteList, addItemToList, updateQuantity, removeItem, toggleChecked, clearCompleted
  } = useShoppingList(user, household);

  const {
      receipts, isLoading: isReceiptsLoading, refreshReceipts, getMonthlySpending, getCategoryBreakdown
  } = useReceipts(user, userProfile?.household_id);

  // --- Global State ---
  const [searchTerm, setSearchTerm] = useState('');
  const [aiSearchQuery, setAiSearchQuery] = useState('');
  const [aiSearchResults, setAiSearchResults] = useState<{ ids: string[] | null, error: string | null, isLoading: boolean }>({ ids: null, error: null, isLoading: false });
  const [ratingFilter, setRatingFilter] = useState<RatingFilter>('all');
  const [typeFilter, setTypeFilter] = useState<TypeFilter>('all');
  const [ownerFilter, setOwnerFilter] = useState<OwnerFilter>('all'); 
  const [sortBy, setSortBy] = useState<SortKey>('date_desc');
  const [collapsedCategories, setCollapsedCategories] = useState<Set<string>>(new Set());

  const [isFilterPanelVisible, setIsFilterPanelVisible] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [isSmartAddLoading, setIsSmartAddLoading] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Receipt State
  const [isReceiptCameraOpen, setIsReceiptCameraOpen] = useState(false);
  const [isProcessingReceipt, setIsProcessingReceipt] = useState(false);
  const [scannedReceiptData, setScannedReceiptData] = useState<(Partial<Receipt> & { items: Partial<ReceiptItem>[] }) | null>(null);
  const [confirmedReceiptForImport, setConfirmedReceiptForImport] = useState<{receipt: Receipt, items: ReceiptItem[]} | null>(null);

  // Modal History for transient modals
  useModalHistory(isFilterPanelVisible, () => setIsFilterPanelVisible(false));
  useModalHistory(isReceiptCameraOpen, () => setIsReceiptCameraOpen(false));
  useModalHistory(!!selectedImage, () => setSelectedImage(null));

  // --- Derived State ---
  const isAnyFilterActive = useMemo(() => searchTerm.trim() !== '' || ratingFilter !== 'all' || typeFilter !== 'all' || aiSearchQuery !== '' || ownerFilter !== 'all', [searchTerm, ratingFilter, typeFilter, aiSearchQuery, ownerFilter]);
  const shoppingListFoodIds = useMemo(() => new Set(shoppingListItems.map(item => item.food_item_id)), [shoppingListItems]);

  const allItems = useMemo(() => {
      const uniqueMap = new Map<string, FoodItem>();
      familyFoodItems.forEach(item => uniqueMap.set(item.id, item));
      foodItems.forEach(item => uniqueMap.set(item.id, item));
      return Array.from(uniqueMap.values());
  }, [foodItems, familyFoodItems]);

  // Filter Logic
  const filteredAndSortedItems = useMemo(() => {
    let items = [...allItems];

    if (aiSearchResults.ids) {
      const idSet = new Set(aiSearchResults.ids);
      items = items.filter(item => idSet.has(item.id));
    }

    const lowerCaseSearchTerm = searchTerm.toLowerCase();

    items = items
      .filter(item => typeFilter === 'all' || item.itemType === typeFilter)
      .filter(item => {
        if (ownerFilter === 'mine') return item.user_id === user?.id; 
        if (ownerFilter === 'family') return item.isFamilyFavorite; 
        return true; 
      })
      .filter(item => {
        if (ratingFilter === 'all') return true;
        if (ratingFilter === 'liked') return item.rating >= 4;
        if (ratingFilter === 'disliked') return item.rating <= 2 && item.rating > 0;
        return true;
      })
      .filter(item =>  !searchTerm.trim() ? true : (
          item.name.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.notes?.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.tags?.join(' ').toLowerCase().includes(lowerCaseSearchTerm) ||
          (item.itemType === 'dish' && (
              item.restaurantName?.toLowerCase().includes(lowerCaseSearchTerm) ||
              item.cuisineType?.toLowerCase().includes(lowerCaseSearchTerm)
          ))
        )
      );

    return [...items].sort((a, b) => {
      switch (sortBy) {
        case 'date_asc': return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
        case 'rating_desc': return b.rating - a.rating;
        case 'rating_asc': return a.rating - b.rating;
        case 'name_asc': return a.name.localeCompare(b.name);
        case 'name_desc': return b.name.localeCompare(a.name);
        case 'date_desc':
        default: return new Date(b.created_at).getTime() - new Date(b.created_at).getTime();
      }
    });
  }, [allItems, searchTerm, ratingFilter, typeFilter, ownerFilter, sortBy, aiSearchResults.ids, user?.id]);

  const hydratedShoppingList = useMemo((): HydratedShoppingListItem[] => {
      const foodItemMap = new Map(allItems.map(item => [item.id, item]));
      const hydratedItems: HydratedShoppingListItem[] = [];
      for (const sli of shoppingListItems) {
        const foodItemDetails = foodItemMap.get(sli.food_item_id);
        if (foodItemDetails) {
          hydratedItems.push({
            ...foodItemDetails,
            shoppingListItemId: sli.id,
            checked: sli.checked,
            added_by_user_id: sli.added_by_user_id,
            checked_by_user_id: sli.checked_by_user_id,
            quantity: sli.quantity,
          });
        }
      }
      return hydratedItems;
  }, [allItems, shoppingListItems]);

  // --- Handlers ---

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
        window.removeEventListener('online', handleOnline);
        window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const handleToggleShoppingList = useCallback((item: FoodItem) => {
      const existingItem = shoppingListItems.find(i => i.food_item_id === item.id);
      if (existingItem) {
          removeItem(existingItem.id);
          triggerHaptic('medium');
          setToastMessage(t('shoppingList.removedToast', { name: item.name }));
      } else {
          addItemToList(item.id, 1);
          triggerHaptic('success');
          setToastMessage(t('shoppingList.addedToast', { name: item.name }));
      }
  }, [shoppingListItems, removeItem, addItemToList, t]);

  const handleToggleFamilyStatus = useCallback(async (item: FoodItem) => {
      if (!user || item.user_id !== user.id) return;
      const newStatus = !item.isFamilyFavorite;
      const { id, user_id, created_at, ...dataToSave } = item;
      const success = await saveItem({ ...dataToSave, isFamilyFavorite: newStatus }, id);
      if (success) {
          triggerHaptic('medium');
          setToastMessage(newStatus ? t('toast.familyShared', { name: item.name }) : t('toast.private', { name: item.name }));
      }
  }, [user, saveItem, t]);

  const handleHouseholdCreateWrapper = useCallback(async (name: string) => {
      try {
          await createHousehold(name);
          setToastMessage(t('shoppingList.joinSuccess', { householdName: name }));
      } catch (e) {}
  }, [createHousehold, t]);

  const handleConversationalSearch = useCallback(async (query: string) => {
    setAiSearchQuery(query);
    setIsFilterPanelVisible(false);
    setAiSearchResults({ ids: null, error: null, isLoading: true });
    try {
      const resultIds = await geminiService.performConversationalSearch(query, foodItems);
      setAiSearchResults({ ids: resultIds, error: null, isLoading: false });
    } catch (e) {
      console.error(e);
      setAiSearchResults({ ids: null, error: t('conversationalSearch.error'), isLoading: false });
    }
  }, [foodItems, t]);

  const clearAllFilters = useCallback(() => {
    setSearchTerm(''); setRatingFilter('all'); setTypeFilter('all'); setOwnerFilter('all');
    setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false });
  }, []);

  const handleSmartQuickAdd = useCallback(async (input: string) => {
      if (!user) return;
      setIsSmartAddLoading(true);
      try {
          const parsedItems = await geminiService.parseShoppingList(input);
          let addedCount = 0;
          for (const parsedItem of parsedItems) {
              let match = allItems.find(i => i.name.toLowerCase() === parsedItem.name.toLowerCase());
              let foodItemId = match?.id;
              if (!foodItemId) {
                  // Auto create item if missing
                  const { createFoodItem } = await import('./services/foodItemService');
                  const newItem = await createFoodItem({ name: parsedItem.name, rating: 0, itemType: 'product', category: parsedItem.category, isFamilyFavorite: !!userProfile?.household_id }, user.id);
                  foodItemId = newItem.id;
                  refreshFoodData();
              }
              if (foodItemId) {
                  addItemToList(foodItemId, parsedItem.quantity);
                  addedCount++;
              }
          }
          if (addedCount > 0) {
              triggerHaptic('success');
              setToastMessage(t('shoppingList.addedAnotherToast', { name: `${addedCount} items` }));
          }
      } catch (e) {
          setToastMessage("Could not process list.");
      } finally {
          setIsSmartAddLoading(false);
      }
  }, [user, allItems, userProfile, addItemToList, refreshFoodData, t]);

  // --- Receipt Handlers ---
  const handleReceiptCapture = async (imageDataUrl: string) => {
      setIsReceiptCameraOpen(false);
      setIsProcessingReceipt(true);
      try {
          const contextItems = hydratedShoppingList.filter(i => i.checked).map(i => ({ id: i.id, name: i.name }));
          const analyzed = await geminiService.analyzeReceiptImage(imageDataUrl, contextItems);
          setScannedReceiptData(analyzed);
      } catch (e) {
          setToastMessage("Could not scan receipt.");
      } finally {
          setIsProcessingReceipt(false);
      }
  };

  const handleSaveReceipt = async (data: Partial<Receipt> & { items: Partial<ReceiptItem>[] }) => {
      if (!user) return;
      try {
          const savedReceipt = await createReceipt(data, user.id, userProfile?.household_id || undefined);
          setScannedReceiptData(null);
          refreshReceipts(); 
          if (savedReceipt && savedReceipt.items && savedReceipt.items.length > 0) {
              setConfirmedReceiptForImport({ receipt: savedReceipt as Receipt, items: savedReceipt.items as ReceiptItem[] });
          } else {
              setToastMessage("Receipt Saved!");
          }
      } catch (e: any) {
          setToastMessage(`Failed to save: ${e.message}`);
      }
  };

  const handleImportReceiptItems = async (selectedItems: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[]) => {
      if (selectedItems.length > 0) {
          const success = await saveItemsBulk(selectedItems);
          if (success) {
              triggerHaptic('success');
              setToastMessage(`Imported ${selectedItems.length} items.`);
          }
      }
      setConfirmedReceiptForImport(null);
  };

  // --- Early Returns ---
  if (!session) return <Auth />;

  const displayError = foodError || householdError || shoppingListError;

  return (
    <>
      <Routes>
        <Route element={
            <Layout 
                shoppingListCount={shoppingListItems.filter(i => !i.checked).length}
                isOnline={isOnline}
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
                isAnyFilterActive={isAnyFilterActive}
                toggleAllCategories={() => {
                    // Simple logic for categories toggle
                    const cats = new Set<string>();
                    filteredAndSortedItems.forEach(item => cats.add(item.category || 'other'));
                    const allCats = Array.from(cats);
                    if (collapsedCategories.size >= allCats.length) setCollapsedCategories(new Set());
                    else setCollapsedCategories(new Set(allCats));
                }}
                isAllCollapsed={filteredAndSortedItems.length > 0 && collapsedCategories.size > 0} // Approximate
                onOpenSettings={() => navigate('/settings')}
                onOpenFilter={() => setIsFilterPanelVisible(true)}
                ownerFilter={ownerFilter} setOwnerFilter={setOwnerFilter}
                aiSearchQuery={aiSearchQuery} clearAiSearch={() => { setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false }); }}
                typeFilter={typeFilter} setTypeFilter={setTypeFilter}
                ratingFilter={ratingFilter} setRatingFilter={setRatingFilter}
                clearAllFilters={clearAllFilters}
            />
        }>
            {/* INVENTORY (Dashboard) */}
            <Route path="/" element={
                <>
                    {displayError && isOnline && <div className="bg-red-100 text-red-700 px-4 py-3 rounded m-4">{displayError}</div>}

                    {aiSearchResults.ids !== null && (
                        <div className="mb-6 p-4 bg-indigo-50 dark:bg-gray-800 rounded-lg flex items-center justify-between border border-indigo-100">
                            <div><h2 className="text-xl font-bold text-indigo-800 dark:text-indigo-200">{t('conversationalSearch.resultsTitle')}</h2><p className="text-sm italic">"{aiSearchQuery}"</p></div>
                            <button onClick={() => { setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false }); }} className="text-sm bg-indigo-200 px-3 py-1.5 rounded-full"><XMarkIcon className="w-4 h-4" /> Clear</button>
                        </div>
                    )}
                    {aiSearchResults.error && <p className="text-red-500 text-center">{aiSearchResults.error}</p>}

                    <Dashboard 
                        items={filteredAndSortedItems}
                        isLoading={isFoodLoading}
                        onAddNew={() => navigate('/add', { state: { startMode: 'camera' } })}
                        onEdit={(id) => navigate(`/edit/${id}`)}
                        onDelete={deleteItem}
                        onViewDetails={(item) => navigate(`/item/${item.id}`)}
                        onAddToShoppingList={handleToggleShoppingList}
                        onToggleFamilyStatus={handleToggleFamilyStatus}
                        shoppingListFoodIds={shoppingListFoodIds}
                        isFiltering={isAnyFilterActive}
                        collapsedCategories={collapsedCategories}
                        onToggleCategory={(category) => setCollapsedCategories(prev => { const n = new Set(prev); n.has(category) ? n.delete(category) : n.add(category); return n; })}
                    />

                    {/* Floating Action Button for Inventory */}
                    <div className="fixed bottom-[calc(5rem+env(safe-area-inset-bottom,0px))] right-6 z-30">
                        <button onClick={() => navigate('/add', { state: { startMode: 'camera' } })} className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold p-4 rounded-full shadow-xl transition-transform transform hover:scale-105 active:scale-95">
                            <CameraIcon className="w-8 h-8" />
                        </button>
                    </div>
                </>
            } />

            {/* SHOPPING LIST */}
            <Route path="/shopping" element={
                <ShoppingListView 
                    allLists={shoppingLists}
                    activeListId={activeShoppingListId}
                    listData={hydratedShoppingList} 
                    household={household}
                    householdMembers={householdMembers}
                    currentUser={user}
                    onRemove={removeItem} 
                    onClear={clearCompleted} 
                    onToggleChecked={toggleChecked} 
                    onSelectList={setActiveShoppingListId}
                    onCreateList={createList}
                    onDeleteList={deleteList}
                    onUpdateQuantity={updateQuantity}
                    onSmartAdd={handleSmartQuickAdd}
                    isSmartAddLoading={isSmartAddLoading}
                />
            } />

            {/* FINANCE */}
            <Route path="/finance" element={
                <FinanceDashboard 
                    monthlyData={getMonthlySpending()}
                    categoryData={getCategoryBreakdown()}
                    totalSpend={0} // calculated inside
                    isLoading={isReceiptsLoading}
                    onScan={() => setIsReceiptCameraOpen(true)}
                />
            } />

            {/* SUB-PAGES */}
            <Route path="/add" element={<ItemFormPage items={allItems} onSave={(data) => saveItem(data)} householdId={userProfile?.household_id || null} />} />
            <Route path="/edit/:id" element={<ItemFormPage items={allItems} onSave={(data) => saveItem(data, data.id)} householdId={userProfile?.household_id || null} />} />
            <Route path="/item/:id" element={<ItemDetailPage items={allItems} currentUser={user} onImageClick={setSelectedImage} />} />
            <Route path="/settings" element={
                <SettingsPage 
                    household={household} 
                    householdMembers={householdMembers} 
                    onHouseholdCreate={handleHouseholdCreateWrapper}
                    onHouseholdLeave={leaveHousehold}
                    onHouseholdDelete={deleteHousehold}
                    error={householdError}
                />
            } />
        </Route>
      </Routes>

      {/* GLOBAL MODALS (Transient State) */}
      {toastMessage && (
         <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-800 dark:bg-gray-200 text-white dark:text-gray-900 text-sm font-semibold py-2 px-4 rounded-full shadow-lg z-50">
            {toastMessage}
        </div>
      )}

      {isFilterPanelVisible && (
        <FilterPanel 
            onClose={() => setIsFilterPanelVisible(false)}
            searchTerm={searchTerm} setSearchTerm={setSearchTerm}
            typeFilter={typeFilter} setTypeFilter={setTypeFilter}
            ratingFilter={ratingFilter} setRatingFilter={setRatingFilter}
            ownerFilter={ownerFilter} setOwnerFilter={setOwnerFilter}
            sortBy={sortBy} setSortBy={setSortBy}
            onReset={clearAllFilters}
            onAiSearch={handleConversationalSearch}
            isAiSearchLoading={aiSearchResults.isLoading}
        />
      )}

      {/* Image Modal (Global for zoom) */}
      {selectedImage && <ImageModal imageUrl={selectedImage} onClose={() => setSelectedImage(null)} />}

      {/* Receipt Modals (Context-specific but global Z-index) */}
      {isReceiptCameraOpen && (
          <CameraCapture onCapture={handleReceiptCapture} onClose={() => setIsReceiptCameraOpen(false)} mode="receipt" />
      )}
      {isProcessingReceipt && (
          <div className="fixed inset-0 bg-black/80 flex flex-col items-center justify-center z-50 text-white">
              <SpinnerIcon className="w-12 h-12 text-white mb-4" />
              <p className="text-lg font-bold">Analyzing...</p>
          </div>
      )}
      {scannedReceiptData && (
          <ReceiptReviewModal receiptData={scannedReceiptData} onSave={handleSaveReceipt} onClose={() => setScannedReceiptData(null)} />
      )}
      {confirmedReceiptForImport && (
          <ReceiptToInventoryModal receipt={confirmedReceiptForImport.receipt} items={confirmedReceiptForImport.items} onConfirm={handleImportReceiptItems} onClose={() => setConfirmedReceiptForImport(null)} />
      )}
    </>
  );
};

import React, { ReactNode } from 'react';
import { useLocation, useNavigate, Link, Outlet } from 'react-router-dom';
import { useTranslation } from '../i18n/index';
import { SettingsIcon, MagnifyingGlassIcon, FunnelIcon, ArrowsPointingOutIcon, ArrowsPointingInIcon, ChevronLeftIcon, XMarkIcon } from './Icons';
import { BottomNavigation } from './BottomNavigation';
import { OfflineIndicator } from './OfflineIndicator';
import { OwnerFilter, RatingFilter, TypeFilter } from '../App';

interface LayoutProps {
  shoppingListCount: number;
  isOnline: boolean;

  // Header Props (Passed down from App logic for now)
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  isAnyFilterActive: boolean;
  toggleAllCategories: () => void;
  isAllCollapsed: boolean;
  onOpenSettings: () => void;
  onOpenFilter: () => void;

  // Filter Display Props
  ownerFilter: OwnerFilter;
  setOwnerFilter: (f: OwnerFilter) => void;
  aiSearchQuery: string;
  clearAiSearch: () => void;
  typeFilter: TypeFilter;
  setTypeFilter: (f: TypeFilter) => void;
  ratingFilter: RatingFilter;
  setRatingFilter: (f: RatingFilter) => void;
  clearAllFilters: () => void;
}

const ActiveFilterPill: React.FC<{onDismiss: () => void, children: React.ReactNode}> = ({onDismiss, children}) => (
  <div className="flex items-center gap-1 bg-indigo-100 text-indigo-800 dark:bg-indigo-600/50 dark:text-indigo-200 text-xs font-semibold px-2 py-1 rounded-full">
      <span>{children}</span>
      <button onClick={onDismiss} className="p-0.5 rounded-full hover:bg-indigo-200 dark:hover:bg-indigo-500/50">
          <XMarkIcon className="w-3 h-3"/>
      </button>
  </div>
);

export const Layout: React.FC<LayoutProps> = ({ 
    shoppingListCount, isOnline,
    searchTerm, setSearchTerm, isAnyFilterActive, toggleAllCategories, isAllCollapsed, onOpenSettings, onOpenFilter,
    ownerFilter, setOwnerFilter, aiSearchQuery, clearAiSearch, typeFilter, setTypeFilter, ratingFilter, setRatingFilter, clearAllFilters
}) => {
  const { t } = useTranslation();
  const location = useLocation();
  const navigate = useNavigate();

  // Route Config
  const isInventory = location.pathname === '/';
  const showBackBtn = location.pathname !== '/' && location.pathname !== '/shopping' && location.pathname !== '/finance';

  // Determine Page Title
  let pageTitle = t('header.title');
  if (location.pathname === '/shopping') pageTitle = t('shoppingList.title');
  if (location.pathname === '/finance') pageTitle = 'Finanzen'; // Should add to i18n
  if (location.pathname === '/settings') pageTitle = t('settings.title');
  if (location.pathname.startsWith('/add')) pageTitle = t('form.addNewButton');
  if (location.pathname.startsWith('/edit')) pageTitle = t('form.editTitle');

  return (
    <div className="min-h-[100dvh] bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans transition-colors duration-300">

        {/* Header */}
        <header className="bg-white/80 dark:bg-gray-800/50 backdrop-blur-sm shadow-md dark:shadow-lg sticky top-0 z-30 pt-safe-top">
            <div className="container mx-auto px-4 py-3 md:py-4">
                <div className="flex justify-between items-center gap-4">
                    {showBackBtn ? (
                        <button onClick={() => navigate(-1)} className="p-2 -ml-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors">
                            <ChevronLeftIcon className="w-6 h-6 text-gray-600 dark:text-gray-300" />
                        </button>
                    ) : (
                        <h1 className="text-xl md:text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-green-500 dark:from-indigo-400 dark:to-green-400 truncate">
                            {pageTitle}
                        </h1>
                    )}

                    {!showBackBtn && (
                        <Link to="/settings" className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors" aria-label={t('settings.title')}>
                            <SettingsIcon className="w-6 h-6 md:w-7 md:h-7 text-gray-600 dark:text-gray-300" />
                        </Link>
                    )}
                </div>

                {/* Search & Filter Bar (Only on Inventory) */}
                {isInventory && (
                    <div className="mt-3 md:mt-4 space-y-3 animate-fade-in">
                        <div className="flex gap-2 items-center">
                            <div className="relative flex-1">
                                <input
                                    type="search"
                                    placeholder={t('header.searchPlaceholder')}
                                    value={searchTerm}
                                    onChange={e => setSearchTerm(e.target.value)}
                                    className="w-full bg-gray-200 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-full shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2 pl-10 pr-4 transition text-sm md:text-base"
                                />
                                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                                    <MagnifyingGlassIcon className="w-5 h-5 text-gray-400 dark:text-gray-500" />
                                </div>
                            </div>

                            <div className="flex items-center gap-1 bg-gray-200 dark:bg-gray-700 rounded-md p-1">
                                <button 
                                    onClick={onOpenFilter} 
                                    className="flex items-center justify-center p-2 rounded-md hover:bg-white dark:hover:bg-gray-600 transition-colors text-gray-700 dark:text-gray-200"
                                    title={t('header.filter.button')}
                                >
                                    <FunnelIcon className="w-5 h-5" />
                                </button>

                                <div className="w-px h-6 bg-gray-300 dark:bg-gray-600 mx-0.5"></div>

                                <button
                                    onClick={toggleAllCategories}
                                    className="flex items-center justify-center p-2 rounded-md hover:bg-white dark:hover:bg-gray-600 transition-colors text-gray-700 dark:text-gray-200"
                                    title={isAllCollapsed ? "Alles ausklappen" : "Alles einklappen"}
                                >
                                    {isAllCollapsed ? <ArrowsPointingOutIcon className="w-5 h-5" /> : <ArrowsPointingInIcon className="w-5 h-5" />}
                                </button>
                            </div>
                        </div>

                        {isAnyFilterActive && (
                            <div className="flex items-center gap-2 flex-wrap pt-1">
                                {ownerFilter !== 'all' && <ActiveFilterPill onDismiss={() => setOwnerFilter('all')}>{t(`header.filter.active.owner.${ownerFilter}`)}</ActiveFilterPill>}
                                {searchTerm.trim() && <ActiveFilterPill onDismiss={() => setSearchTerm('')}>{t('header.filter.active.search', { term: searchTerm })}</ActiveFilterPill>}
                                {aiSearchQuery && <ActiveFilterPill onDismiss={clearAiSearch}>{t('header.filter.active.aiSearch', { term: aiSearchQuery })}</ActiveFilterPill>}
                                {typeFilter !== 'all' && <ActiveFilterPill onDismiss={() => setTypeFilter('all')}>{t(`header.filter.active.type.${typeFilter}`)}</ActiveFilterPill>}
                                {ratingFilter !== 'all' && <ActiveFilterPill onDismiss={() => setRatingFilter('all')}>{t(`header.filter.active.rating.${ratingFilter}`)}</ActiveFilterPill>}
                                <button onClick={clearAllFilters} className="text-xs text-indigo-600 dark:text-indigo-400 hover:underline">{t('header.filter.clearAll')}</button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </header>

        <OfflineIndicator isOnline={isOnline} />

        <main className="container mx-auto p-4 md:p-8 pb-32">
            <Outlet />
        </main>

        <BottomNavigation shoppingListCount={shoppingListCount} />
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { FoodItem, FoodItemType, NutriScore, GroceryCategory } from '../types';
import { analyzeFoodImage, analyzeIngredientsImage, hasValidApiKey, findNearbyRestaurants, BoundingBox } from '../services/geminiService';
import { fetchProductFromOpenDatabase, searchProductByNameFromOpenDatabase } from '../services/openFoodFactsService';
import { translateTexts } from '../services/translationService';
import { useTranslation } from '../i18n/index';
import { useAppSettings } from '../contexts/AppSettingsContext';

interface UseFoodFormLogicProps {
  initialData?: FoodItem | null;
  initialItemType?: FoodItemType;
  onSaveItem: (item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>) => void;
  onCancel: () => void;
  startMode?: 'barcode' | 'camera' | 'none';
}

export const useFoodFormLogic = ({ initialData, initialItemType = 'product', onSaveItem, onCancel, startMode = 'none' }: UseFoodFormLogicProps) => {
  const { t, language } = useTranslation();
  const { isAiEnabled, isOffSearchEnabled } = useAppSettings();
  const [apiKeyValid, setApiKeyValid] = useState(false);

  useEffect(() => {
    setApiKeyValid(hasValidApiKey());
  }, []);

  const isAiAvailable = isAiEnabled && apiKeyValid;

  // --- Form State ---
  const [itemType, setItemType] = useState<FoodItemType>(initialItemType);
  const [name, setName] = useState('');
  const [rating, setRating] = useState(0);
  const [notes, setNotes] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [tags, setTags] = useState('');
  // UX Improvement: Default to true for sharing
  const [isFamilyFavorite, setIsFamilyFavorite] = useState(true);
  const [category, setCategory] = useState<GroceryCategory>('other');

  // Product-specific
  const [nutriScore, setNutriScore] = useState<NutriScore | ''>('');
  const [calories, setCalories] = useState<number | ''>(''); 
  const [purchaseLocation, setPurchaseLocation] = useState('');
  const [ingredients, setIngredients] = useState<string[]>([]);
  const [allergens, setAllergens] = useState<string[]>([]);
  const [dietary, setDietary] = useState({
    isLactoseFree: false,
    isVegan: false,
    isGlutenFree: false,
  });

  // Dish-specific
  const [restaurantName, setRestaurantName] = useState('');
  const [cuisineType, setCuisineType] = useState('');
  const [price, setPrice] = useState<number | ''>('');
  const [isFindingRestaurants, setIsFindingRestaurants] = useState(false);
  const [nearbyRestaurants, setNearbyRestaurants] = useState<{name: string, cuisine?: string}[]>([]);
  const [locationError, setLocationError] = useState<string | null>(null);

  // --- UI/Flow State ---
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isBarcodeScannerOpen, setIsBarcodeScannerOpen] = useState(false);
  const [isSpeechModalOpen, setIsSpeechModalOpen] = useState(false);
  const [isNameSearchLoading, setIsNameSearchLoading] = useState(false);
  const [scanMode, setScanMode] = useState<'main' | 'ingredients'>('main');
  const [uncroppedImage, setUncroppedImage] = useState<string | null>(null);
  const [suggestedCrop, setSuggestedCrop] = useState<BoundingBox | null | undefined>(null);
  const [isCropperOpen, setIsCropperOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [analysisProgress, setAnalysisProgress] = useState({ active: false, message: '' });
  const [highlightedFields, setHighlightedFields] = useState<string[]>([]);
  const [isIngredientsLoading, setIngredientsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [autoExpandDetails, setAutoExpandDetails] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Initialization ---
  const resetFormState = useCallback(() => {
    setItemType(initialItemType);
    setName('');
    setRating(0);
    setNotes('');
    setImage(null);
    setNutriScore('');
    setCalories('');
    setPurchaseLocation('');
    setTags('');
    // Reset to true by default for new items
    setIsFamilyFavorite(true);
    setIngredients([]);
    setAllergens([]);
    setDietary({ isLactoseFree: false, isVegan: false, isGlutenFree: false });
    setRestaurantName('');
    setCuisineType('');
    setPrice('');

    // Smart default category based on initial type
    const defaultCat = initialItemType === 'drugstore' ? 'personal_care' : (initialItemType === 'dish' ? 'restaurant_food' : 'other');
    setCategory(defaultCat);

    setError(null);
    setIsLoading(false);
    setAutoExpandDetails(false);
    if(fileInputRef.current) fileInputRef.current.value = '';
  }, [initialItemType]);

  useEffect(() => {
    if (initialData) {
      setItemType(initialData.itemType);
      setName(initialData.name);
      setRating(initialData.rating);
      setNotes(initialData.notes || '');
      setImage(initialData.image || null);
      setTags(initialData.tags?.join(', ') || '');
      // When editing, respect the existing value (default to false only if undefined in DB, which shouldn't happen)
      setIsFamilyFavorite(initialData.isFamilyFavorite ?? false);
      setPrice(initialData.price ?? '');

      // Strict category initialization: Use data from DB if exists, otherwise fallback intelligently
      if (initialData.category) {
          setCategory(initialData.category);
      } else {
          // Fallback only if no category saved
          const fallbackCat = initialData.itemType === 'drugstore' ? 'personal_care' : (initialData.itemType === 'dish' ? 'restaurant_food' : 'other');
          setCategory(fallbackCat);
      }

      if(initialData.itemType === 'product' || initialData.itemType === 'drugstore') {
        setNutriScore(initialData.nutriScore || '');
        setCalories(initialData.calories !== undefined && initialData.calories !== null ? initialData.calories : '');
        setPurchaseLocation(initialData.purchaseLocation?.join(', ') || '');
        setIngredients(initialData.ingredients || []);
        setAllergens(initialData.allergens || []);
        setDietary({
          isLactoseFree: initialData.isLactoseFree || false,
          isVegan: initialData.isVegan || false,
          isGlutenFree: initialData.isGlutenFree || false,
        });
        if (initialData.nutriScore || (initialData.purchaseLocation?.length || 0) > 0 || initialData.isVegan || (initialData.calories !== undefined && initialData.calories !== null)) {
            setAutoExpandDetails(true);
        }
      } else {
        setRestaurantName(initialData.restaurantName || '');
        setCuisineType(initialData.cuisineType || '');
      }
    } else {
      resetFormState();
    }
  }, [initialData, resetFormState]);

  useEffect(() => {
      if (initialData) return; 

      if (startMode === 'barcode') {
          setIsBarcodeScannerOpen(true);
      } else if (startMode === 'camera') {
          setScanMode('main');
          setIsCameraOpen(true);
      }
  }, [startMode, initialData]);

  useEffect(() => {
    if (highlightedFields.length > 0) {
      const timer = setTimeout(() => {
        setHighlightedFields([]);
      }, 2500);
      return () => clearTimeout(timer);
    }
  }, [highlightedFields]);

  // One-way binding: Category implies Type.
  // We use this to auto-switch the form mode when a user selects a specific category.
  useEffect(() => {
      if (category === 'restaurant_food') {
          setItemType('dish');
      } else if (category === 'personal_care' || category === 'household') {
          setItemType('drugstore');
      } else {
          setItemType('product');
      }
  }, [category]);

  // --- Logic Handlers ---

  const handleFindNearby = useCallback(() => {
    setLocationError(null);
    setNearbyRestaurants([]);
    setIsFindingRestaurants(true);

    if (!navigator.geolocation) {
      setLocationError(t('form.error.geolocationUnsupported'));
      setIsFindingRestaurants(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const restaurants = await findNearbyRestaurants(latitude, longitude);
          if (restaurants.length > 0) {
              setNearbyRestaurants(restaurants);
          } else {
              setLocationError(t('form.error.findRestaurants'));
          }
        } catch (err) {
          setLocationError(t('form.error.findRestaurants'));
          console.error(err);
        } finally {
          setIsFindingRestaurants(false);
        }
      },
      (error) => {
        setLocationError(t('form.error.geolocationPermission'));
        console.error(error);
        setIsFindingRestaurants(false);
      },
      { timeout: 10000 }
    );
  }, [t]);

  const handleScanMainImage = useCallback(() => {
    setScanMode('main');
    setIsCameraOpen(true);
  }, []);

  const handleScanIngredients = useCallback(() => {
    setScanMode('ingredients');
    setIsCameraOpen(true);
  }, []);

  // Process Name with the CORRECT database type
  const processSpokenProductName = useCallback(async (productName: string) => {
    if (!productName || !isOffSearchEnabled) return;

    setIsNameSearchLoading(true);
    setError(null);
    try {
      // Use the current itemType to decide which DB to search (product=Food, drugstore=Beauty)
      const offResult = await searchProductByNameFromOpenDatabase(productName, itemType, language);

      let mergedData = {
          tags: offResult.tags || [],
          nutriScore: (offResult.nutriScore || '') as NutriScore | '',
          calories: offResult.calories,
          ingredients: offResult.ingredients || [],
          allergens: offResult.allergens || [],
          isLactoseFree: offResult.isLactoseFree || false,
          isVegan: offResult.isVegan || false,
          isGlutenFree: offResult.isGlutenFree || false,
      };

      const newHighlightedFields: string[] = [];
      if (mergedData.tags.length > 0) newHighlightedFields.push('tags');
      if (mergedData.nutriScore) newHighlightedFields.push('nutriScore');
      if (mergedData.calories !== undefined) newHighlightedFields.push('calories');

      setTags(current => (current ? `${current}, ` : '') + mergedData.tags.join(', '));
      // For spoken/merged data, we prefer keeping existing data if the new data is empty, but generally overwrite if new data exists
      setNutriScore(current => mergedData.nutriScore || current);
      setCalories(current => (mergedData.calories !== undefined && mergedData.calories !== null) ? mergedData.calories : current);
      setIngredients(current => mergedData.ingredients.length > 0 ? mergedData.ingredients : current);
      setAllergens(current => mergedData.allergens.length > 0 ? mergedData.allergens : current);
      setDietary(current => ({
          isLactoseFree: current.isLactoseFree || mergedData.isLactoseFree,
          isVegan: current.isVegan || mergedData.isVegan,
          isGlutenFree: current.isGlutenFree || mergedData.isGlutenFree,
      }));
      setHighlightedFields(newHighlightedFields);
      if (mergedData.tags.length > 0 || mergedData.nutriScore || mergedData.calories !== undefined) setAutoExpandDetails(true);

    } catch (e) {
      console.error("Error searching by product name:", e);
    } finally {
      setIsNameSearchLoading(false);
    }
  }, [isOffSearchEnabled, language, itemType]);

  const handleDictationResult = useCallback((transcript: string) => {
    setIsSpeechModalOpen(false);
    if (transcript) {
      setName(transcript);
      if (itemType === 'product' || itemType === 'drugstore') {
        processSpokenProductName(transcript);
      }
    }
  }, [itemType, processSpokenProductName]);

  const handleBarcodeScanned = useCallback(async (barcode: string) => {
    setIsBarcodeScannerOpen(false);
    setError(null);

    if (!isOffSearchEnabled) {
      setError(t('form.error.offSearchDisabled'));
      return;
    }

    setIsLoading(true);
    try {
      // Use smart fetcher (Food -> fallback Beauty)
      const productData = await fetchProductFromOpenDatabase(barcode);

      let finalName = productData.name || '';
      let finalTags = productData.tags || [];
      let finalIngredients = productData.ingredients || [];
      let finalAllergens = productData.allergens || [];

      if (language !== 'en' && isAiAvailable) {
        const textsToTranslate = [finalName, ...finalTags, ...finalIngredients, ...finalAllergens];
        try {
          const translated = await translateTexts(textsToTranslate, language);
          let currentIndex = 0;
          finalName = translated[currentIndex++];
          finalTags = translated.slice(currentIndex, currentIndex + finalTags.length);
          currentIndex += finalTags.length;
          finalIngredients = translated.slice(currentIndex, currentIndex + finalIngredients.length);
          currentIndex += finalIngredients.length;
          finalAllergens = translated.slice(currentIndex, currentIndex + finalAllergens.length);
        } catch (e) {
          console.error("Failed to translate OFF results for form", e);
        }
      }

      setName(finalName);
      setTags(finalTags.join(', '));
      setNutriScore((productData.nutriScore?.toUpperCase() as NutriScore) || '');
      setCalories(productData.calories !== undefined && productData.calories !== null ? productData.calories : '');
      setPurchaseLocation(productData.purchaseLocation?.join(', ') || '');
      setImage(productData.image || null);
      setIngredients(finalIngredients);
      setAllergens(finalAllergens);
      setDietary({
        isLactoseFree: productData.isLactoseFree || false,
        isVegan: productData.isVegan || false,
        isGlutenFree: productData.isGlutenFree || false,
      });

      // Auto-switch item type based on API Result
      if (productData.itemType === 'drugstore') {
          setItemType('drugstore');
          setCategory('personal_care');
      } else {
          setItemType('product');
          setCategory('other'); 
      }

      setAutoExpandDetails(true);

    } catch(e) {
       console.error(e);
       const errorMessage = e instanceof Error ? e.message : t('form.error.barcodeError');
       setError(errorMessage);
    } finally {
        setIsLoading(false);
    }
  }, [isOffSearchEnabled, t, language, isAiAvailable]);

  const textsNeedTranslation = useCallback((data: {name:string, tags:string[], ingredients:string[], allergens:string[]}) => {
    return data.name || data.tags.length > 0 || data.ingredients.length > 0 || data.allergens.length > 0;
  }, []);

  const handleImageFromCamera = useCallback(async (imageDataUrl: string) => {
    setIsCameraOpen(false);
    setError(null);

    if (!isAiAvailable) {
      setUncroppedImage(imageDataUrl);
      setSuggestedCrop(null);
      setIsCropperOpen(true);
      return;
    }

    if (scanMode === 'main') {
      let progressInterval: number | undefined;
      try {
        const progressMessages = [
            t('form.aiProgress.readingName'),
            t('form.aiProgress.findingScore'),
            t('form.aiProgress.generatingTags'),
            t('form.aiProgress.locatingProduct')
        ];

        setAnalysisProgress({ active: true, message: progressMessages[0] });
        let messageIndex = 0;
        progressInterval = window.setInterval(() => {
            messageIndex = (messageIndex + 1) % progressMessages.length;
            setAnalysisProgress(prev => ({ ...prev, message: progressMessages[messageIndex] }));
        }, 1500);

        // API Call now returns the optimized image alongside data
        const aiResult = await analyzeFoodImage(imageDataUrl);

        if(progressInterval) clearInterval(progressInterval);

        let mergedData = {
            name: aiResult.name || '',
            tags: aiResult.tags || [],
            nutriScore: (aiResult.nutriScore || '') as NutriScore | '',
            ingredients: [] as string[],
            allergens: [] as string[],
            isLactoseFree: false,
            isVegan: false,
            isGlutenFree: false,
        };

        if (language !== 'en' && textsNeedTranslation(mergedData)) {
            const textsToTranslate = [
                mergedData.name, ...mergedData.tags
            ];
            try {
                const translated = await translateTexts(textsToTranslate, language);
                if (translated.length === textsToTranslate.length) {
                    let i = 0;
                    mergedData.name = translated[i++];
                    mergedData.tags = translated.slice(i, i + mergedData.tags.length);
                }
            } catch (e) {
                console.error("Failed to translate AI results", e);
            }
        }

        // Resetting state with new image data - STRICT OVERWRITE
        setName(mergedData.name);
        setTags(mergedData.tags.join(', '));
        setNutriScore(mergedData.nutriScore);

        // Critical Fix: Explicitly reset potentially stale data from previous scans
        setCalories('');
        setIngredients([]);
        setAllergens([]);
        setDietary({ isLactoseFree: false, isVegan: false, isGlutenFree: false });

        // Handle Item Type & Category from AI
        let currentItemType: FoodItemType = 'product';

        if (aiResult.itemType) {
             if (aiResult.itemType === 'dish') {
                 setItemType('dish');
                 setCategory('restaurant_food');
                 currentItemType = 'dish';
             } else if (aiResult.itemType === 'drugstore') {
                 setItemType('drugstore');
                 setCategory('personal_care');
                 currentItemType = 'drugstore';
             } else {
                 setItemType('product');
                 setCategory(aiResult.category || 'other');
                 currentItemType = 'product';
             }
        }

        const newHighlightedFields: string[] = [];
        if (mergedData.name) newHighlightedFields.push('name');
        if (mergedData.tags.length > 0) newHighlightedFields.push('tags');
        if (mergedData.nutriScore) newHighlightedFields.push('nutriScore');
        if (aiResult.category) newHighlightedFields.push('category');
        setHighlightedFields(newHighlightedFields);

        if (mergedData.nutriScore || mergedData.tags.length > 0) setAutoExpandDetails(true);

        // FIX: Use the optimized image for the cropper to ensure coordinates align
        setUncroppedImage(aiResult.image || imageDataUrl);
        setSuggestedCrop(aiResult.boundingBox);
        setIsCropperOpen(true);
        setIsLoading(false);

        if (currentItemType === 'dish') {
            handleFindNearby();
        } else if (mergedData.name && isOffSearchEnabled) {
            setAnalysisProgress({ active: true, message: t('form.aiProgress.searchingDatabase') });

            try {
                // Pass currentItemType so we search the correct database (Food vs Beauty)
                const offResult = await searchProductByNameFromOpenDatabase(mergedData.name, currentItemType, language);

                // Merge tags (keep visual tags, add DB tags)
                setTags(prev => {
                    const existing = prev ? prev.split(',').map(s => s.trim()) : [];
                    const newTags = offResult.tags || [];
                    const combined = Array.from(new Set([...existing, ...newTags]));
                    return combined.join(', ');
                });

                // Strictly overwrite metadata with database results.
                setNutriScore((offResult.nutriScore as NutriScore) || '');
                // Correctly handle 0 kcal. 
                setCalories((offResult.calories !== undefined && offResult.calories !== null) ? offResult.calories : '');
                setIngredients(offResult.ingredients || []);
                setAllergens(offResult.allergens || []);
                setDietary({
                    isLactoseFree: !!offResult.isLactoseFree,
                    isVegan: !!offResult.isVegan,
                    isGlutenFree: !!offResult.isGlutenFree,
                });

                setHighlightedFields(prev => {
                    const next = [...prev];
                    if (offResult.nutriScore && !prev.includes('nutriScore')) next.push('nutriScore');
                    if (offResult.calories !== undefined && !prev.includes('calories')) next.push('calories');
                    if ((offResult.tags?.length || 0) > 0 && !prev.includes('tags')) next.push('tags');
                    return next;
                });

                setAutoExpandDetails(true);

            } catch (offError) {
                console.warn("Could not fetch supplementary data from Open Database:", offError);
            } finally {
                setAnalysisProgress({ active: false, message: '' });
            }
        } else {
             setAnalysisProgress({ active: false, message: '' });
        }

      } catch (e) {
        if(progressInterval) clearInterval(progressInterval);
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : t('form.error.genericAiError');
        setError(errorMessage);
        setUncroppedImage(imageDataUrl);
        setSuggestedCrop(null);
        setIsCropperOpen(true);
        setAnalysisProgress({ active: false, message: '' });
      } 
    } else { // scanMode === 'ingredients'
      setIngredientsLoading(true);
      try {
        const result = await analyzeIngredientsImage(imageDataUrl);

        let finalIngredients = result.ingredients || [];
        let finalAllergens = result.allergens || [];

        if (language !== 'en' && (finalIngredients.length > 0 || finalAllergens.length > 0)) {
            try {
                const textsToTranslate = [...finalIngredients, ...finalAllergens];
                const translated = await translateTexts(textsToTranslate, language);
                if (translated.length === textsToTranslate.length) {
                    finalIngredients = translated.slice(0, finalIngredients.length);
                    finalAllergens = translated.slice(finalIngredients.length);
                }
            } catch(e) {
                console.error("Failed to translate ingredients AI results for form", e);
            }
        }

        setIngredients(finalIngredients);
        setAllergens(finalAllergens);
        setDietary({
            isLactoseFree: result.isLactoseFree,
            isVegan: result.isVegan,
            isGlutenFree: result.isGlutenFree,
        });
        setAutoExpandDetails(true);
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : t('form.error.ingredientsAiError');
        setError(errorMessage);
      } finally {
        setIngredientsLoading(false);
      }
    }
  }, [isAiAvailable, scanMode, t, isOffSearchEnabled, language, textsNeedTranslation, handleFindNearby]);

  const handleCropComplete = useCallback((croppedImageUrl: string) => {
    setImage(croppedImageUrl);
    setIsCropperOpen(false);
    setUncroppedImage(null);
    setSuggestedCrop(null);
  }, []);

  const handleCropCancel = useCallback(() => {
    if (uncroppedImage) setImage(uncroppedImage);
    setIsCropperOpen(false);
    setUncroppedImage(null);
    setSuggestedCrop(null);
  }, [uncroppedImage]);

  const handleFileChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setScanMode('main');
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleImageFromCamera(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  }, [handleImageFromCamera]);

  const handleDietaryChange = useCallback((key: keyof typeof dietary) => {
    setDietary(prev => ({...prev, [key]: !prev[key]}));
  }, []);

  const removeImage = useCallback(() => {
    setImage(null);
    if(fileInputRef.current) fileInputRef.current.value = '';
  }, []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!name.trim()) {
      setError(t('form.error.nameAndRating'));
      return;
    }
    if (rating === 0) {
      setError(t('form.error.nameAndRating'));
      return;
    }

    const commonData = {
      name,
      rating,
      notes: notes || undefined,
      image: image || undefined,
      tags: tags ? tags.split(',').map(tag => tag.trim()).filter(Boolean) : undefined,
      itemType,
      // CRITICAL: Force category to be present. If empty string or undefined, use 'other'.
      category: category || 'other', 
      isFamilyFavorite,
      // Pass price for all types, allowing products to have a price too
      price: price !== '' ? Number(price) : undefined,
    };

    if (itemType === 'product' || itemType === 'drugstore') {
        onSaveItem({
          ...commonData,
          nutriScore: nutriScore || undefined,
          calories: calories !== '' ? Number(calories) : undefined,
          purchaseLocation: purchaseLocation ? purchaseLocation.split(',').map(loc => loc.trim()).filter(Boolean) : undefined,
          ingredients: ingredients.length > 0 ? ingredients : undefined,
          allergens: allergens.length > 0 ? allergens : undefined,
          isLactoseFree: dietary.isLactoseFree,
          isVegan: dietary.isVegan,
          isGlutenFree: dietary.isGlutenFree,
        });
    } else { // itemType === 'dish'
        onSaveItem({
          ...commonData,
          restaurantName: restaurantName || undefined,
          cuisineType: cuisineType || undefined,
        });
    }
  }, [name, rating, t, notes, image, tags, itemType, category, onSaveItem, nutriScore, calories, purchaseLocation, ingredients, allergens, dietary, restaurantName, cuisineType, price, isFamilyFavorite]);

  const handleSelectRestaurant = useCallback((restaurantIndex: number) => {
      const selected = nearbyRestaurants[restaurantIndex];
      if(selected) {
          setRestaurantName(selected.name);
          if (selected.cuisine) {
              setCuisineType(selected.cuisine);
          }
          setNearbyRestaurants([]); 
      }
  }, [nearbyRestaurants]);

  return {
    formState: {
      name, rating, notes, image, tags, isFamilyFavorite, category,
      nutriScore, calories, purchaseLocation, ingredients, allergens, dietary,
      restaurantName, cuisineType, price, itemType
    },
    formSetters: {
      setName, setRating, setNotes, setImage, setTags, setIsFamilyFavorite, setCategory,
      setNutriScore, setCalories, setPurchaseLocation, setIngredients, setAllergens, setRestaurantName, setCuisineType, setPrice, setItemType, setAutoExpandDetails
    },
    uiState: {
      isCameraOpen, isBarcodeScannerOpen, isSpeechModalOpen, isNameSearchLoading,
      isCropperOpen, uncroppedImage, suggestedCrop, isLoading, analysisProgress,
      highlightedFields, isIngredientsLoading, error, isFindingRestaurants,
      nearbyRestaurants, locationError, isAiAvailable, scanMode, autoExpandDetails
    },
    uiSetters: {
      setIsCameraOpen, setIsBarcodeScannerOpen, setIsSpeechModalOpen, setIsCropperOpen, setError
    },
    actions: {
      handleScanMainImage, handleScanIngredients, handleBarcodeScanned,
      handleImageFromCamera, handleDictationResult, handleCropComplete,
      handleCropCancel, handleFileChange, handleDietaryChange, handleFindNearby,
      handleSelectRestaurant, removeImage, handleSubmit
    },
    fileInputRef
  };
};

