interface UseFoodFormLogicProps {
  initialData?: FoodItem | null;
  initialItemType?: FoodItemType;
  onSaveItem: (item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>) => void;
  onCancel: () => void;
  startMode?: 'barcode' | 'camera' | 'none';
}

export const useFoodFormLogic = ({ initialData, initialItemType = 'product', onSaveItem, onCancel, startMode = 'none' }: UseFoodFormLogicProps) => {
  const { t, language } = useTranslation();
  const { isAiEnabled, isOffSearchEnabled } = useAppSettings();
  const [apiKeyValid, setApiKeyValid] = useState(false);

  useEffect(() => {
    setApiKeyValid(hasValidApiKey());
  }, []);

  const isAiAvailable = isAiEnabled && apiKeyValid;

  // --- Form State ---
  const [itemType, setItemType] = useState<FoodItemType>(initialItemType);
  const [name, setName] = useState('');
  const [rating, setRating] = useState(0);
  const [notes, setNotes] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [tags, setTags] = useState('');
  // UX Improvement: Default to true for sharing
  const [isFamilyFavorite, setIsFamilyFavorite] = useState(true);
  const [category, setCategory] = useState<GroceryCategory>('other');

  // Product-specific
  const [nutriScore, setNutriScore] = useState<NutriScore | ''>('');
  const [calories, setCalories] = useState<number | ''>(''); 
  const [purchaseLocation, setPurchaseLocation] = useState('');
  const [ingredients, setIngredients] = useState<string[]>([]);
  const [allergens, setAllergens] = useState<string[]>([]);
  const [dietary, setDietary] = useState({
    isLactoseFree: false,
    isVegan: false,
    isGlutenFree: false,
  });
  const [expiryDate, setExpiryDate] = useState(''); // YYYY-MM-DD

  // Dish-specific
  const [restaurantName, setRestaurantName] = useState('');
  const [cuisineType, setCuisineType] = useState('');
  const [price, setPrice] = useState<number | ''>('');
  const [isFindingRestaurants, setIsFindingRestaurants] = useState(false);
  const [nearbyRestaurants, setNearbyRestaurants] = useState<{name: string, cuisine?: string}[]>([]);
  const [locationError, setLocationError] = useState<string | null>(null);

  // --- UI/Flow State ---
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isBarcodeScannerOpen, setIsBarcodeScannerOpen] = useState(false);
  const [isSpeechModalOpen, setIsSpeechModalOpen] = useState(false);
  const [isNameSearchLoading, setIsNameSearchLoading] = useState(false);
  const [scanMode, setScanMode] = useState<'main' | 'ingredients'>('main');
  const [uncroppedImage, setUncroppedImage] = useState<string | null>(null);
  const [suggestedCrop, setSuggestedCrop] = useState<BoundingBox | null | undefined>(null);
  const [isCropperOpen, setIsCropperOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [analysisProgress, setAnalysisProgress] = useState({ active: false, message: '' });
  const [highlightedFields, setHighlightedFields] = useState<string[]>([]);
  const [isIngredientsLoading, setIngredientsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [autoExpandDetails, setAutoExpandDetails] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Initialization ---
  const resetFormState = useCallback(() => {
    setItemType(initialItemType);
    setName('');
    setRating(0);
    setNotes('');
    setImage(null);
    setNutriScore('');
    setCalories('');
    setPurchaseLocation('');
    setTags('');
    // Reset to true by default for new items
    setIsFamilyFavorite(true);
    setIngredients([]);
    setAllergens([]);
    setDietary({ isLactoseFree: false, isVegan: false, isGlutenFree: false });
    setRestaurantName('');
    setCuisineType('');
    setPrice('');
    setExpiryDate('');

    // Smart default category based on initial type
    const defaultCat = initialItemType === 'drugstore' ? 'personal_care' : (initialItemType === 'dish' ? 'restaurant_food' : 'other');
    setCategory(defaultCat);

    setError(null);
    setIsLoading(false);
    setAutoExpandDetails(false);
    if(fileInputRef.current) fileInputRef.current.value = '';
  }, [initialItemType]);

  useEffect(() => {
    if (initialData) {
      setItemType(initialData.itemType);
      setName(initialData.name);
      setRating(initialData.rating);
      setNotes(initialData.notes || '');
      setImage(initialData.image || null);
      setTags(initialData.tags?.join(', ') || '');
      // When editing, respect the existing value (default to false only if undefined in DB, which shouldn't happen)
      setIsFamilyFavorite(initialData.isFamilyFavorite ?? false);
      setPrice(initialData.price ?? '');
      setExpiryDate(initialData.expiryDate || '');

      // Strict category initialization: Use data from DB if exists, otherwise fallback intelligently
      if (initialData.category) {
          setCategory(initialData.category);
      } else {
          // Fallback only if no category saved
          const fallbackCat = initialData.itemType === 'drugstore' ? 'personal_care' : (initialData.itemType === 'dish' ? 'restaurant_food' : 'other');
          setCategory(fallbackCat);
      }

      if(initialData.itemType === 'product' || initialData.itemType === 'drugstore') {
        setNutriScore(initialData.nutriScore || '');
        setCalories(initialData.calories !== undefined && initialData.calories !== null ? initialData.calories : '');
        setPurchaseLocation(initialData.purchaseLocation?.join(', ') || '');
        setIngredients(initialData.ingredients || []);
        setAllergens(initialData.allergens || []);
        setDietary({
          isLactoseFree: initialData.isLactoseFree || false,
          isVegan: initialData.isVegan || false,
          isGlutenFree: initialData.isGlutenFree || false,
        });
        if (initialData.nutriScore || (initialData.purchaseLocation?.length || 0) > 0 || initialData.isVegan || (initialData.calories !== undefined && initialData.calories !== null)) {
            setAutoExpandDetails(true);
        }
      } else {
        setRestaurantName(initialData.restaurantName || '');
        setCuisineType(initialData.cuisineType || '');
      }
    } else {
      resetFormState();
    }
  }, [initialData, resetFormState]);

  useEffect(() => {
      if (initialData) return; 

      if (startMode === 'barcode') {
          setIsBarcodeScannerOpen(true);
      } else if (startMode === 'camera') {
          setScanMode('main');
          setIsCameraOpen(true);
      }
  }, [startMode, initialData]);

  useEffect(() => {
    if (highlightedFields.length > 0) {
      const timer = setTimeout(() => {
        setHighlightedFields([]);
      }, 2500);
      return () => clearTimeout(timer);
    }
  }, [highlightedFields]);

  // One-way binding: Category implies Type.
  // We use this to auto-switch the form mode when a user selects a specific category.
  useEffect(() => {
      if (category === 'restaurant_food') {
          setItemType('dish');
      } else if (category === 'personal_care' || category === 'household') {
          setItemType('drugstore');
      } else {
          setItemType('product');
      }
  }, [category]);

  // --- Logic Handlers ---

  const handleFindNearby = useCallback(() => {
    setLocationError(null);
    setNearbyRestaurants([]);
    setIsFindingRestaurants(true);

    if (!navigator.geolocation) {
      setLocationError(t('form.error.geolocationUnsupported'));
      setIsFindingRestaurants(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const restaurants = await findNearbyRestaurants(latitude, longitude);
          if (restaurants.length > 0) {
              setNearbyRestaurants(restaurants);
          } else {
              setLocationError(t('form.error.findRestaurants'));
          }
        } catch (err) {
          setLocationError(t('form.error.findRestaurants'));
          console.error(err);
        } finally {
          setIsFindingRestaurants(false);
        }
      },
      (error) => {
        setLocationError(t('form.error.geolocationPermission'));
        console.error(error);
        setIsFindingRestaurants(false);
      },
      { timeout: 10000 }
    );
  }, [t]);

  const handleScanMainImage = useCallback(() => {
    setScanMode('main');
    setIsCameraOpen(true);
  }, []);

  const handleScanIngredients = useCallback(() => {
    setScanMode('ingredients');
    setIsCameraOpen(true);
  }, []);

  // Process Name with the CORRECT database type
  const processSpokenProductName = useCallback(async (productName: string) => {
    if (!productName || !isOffSearchEnabled) return;

    setIsNameSearchLoading(true);
    setError(null);
    try {
      // Use the current itemType to decide which DB to search (product=Food, drugstore=Beauty)
      const offResult = await searchProductByNameFromOpenDatabase(productName, itemType, language);

      let mergedData = {
          tags: offResult.tags || [],
          nutriScore: (offResult.nutriScore || '') as NutriScore | '',
          calories: offResult.calories,
          ingredients: offResult.ingredients || [],
          allergens: offResult.allergens || [],
          isLactoseFree: offResult.isLactoseFree || false,
          isVegan: offResult.isVegan || false,
          isGlutenFree: offResult.isGlutenFree || false,
      };

      const newHighlightedFields: string[] = [];
      if (mergedData.tags.length > 0) newHighlightedFields.push('tags');
      if (mergedData.nutriScore) newHighlightedFields.push('nutriScore');
      if (mergedData.calories !== undefined) newHighlightedFields.push('calories');

      setTags(current => (current ? `${current}, ` : '') + mergedData.tags.join(', '));
      // For spoken/merged data, we prefer keeping existing data if the new data is empty, but generally overwrite if new data exists
      setNutriScore(current => mergedData.nutriScore || current);
      setCalories(current => (mergedData.calories !== undefined && mergedData.calories !== null) ? mergedData.calories : current);
      setIngredients(current => mergedData.ingredients.length > 0 ? mergedData.ingredients : current);
      setAllergens(current => mergedData.allergens.length > 0 ? mergedData.allergens : current);
      setDietary(current => ({
          isLactoseFree: current.isLactoseFree || mergedData.isLactoseFree,
          isVegan: current.isVegan || mergedData.isVegan,
          isGlutenFree: current.isGlutenFree || mergedData.isGlutenFree,
      }));
      setHighlightedFields(newHighlightedFields);
      if (mergedData.tags.length > 0 || mergedData.nutriScore || mergedData.calories !== undefined) setAutoExpandDetails(true);

    } catch (e) {
      console.error("Error searching by product name:", e);
    } finally {
      setIsNameSearchLoading(false);
    }
  }, [isOffSearchEnabled, language, itemType]);

  const handleDictationResult = useCallback((transcript: string) => {
    setIsSpeechModalOpen(false);
    if (transcript) {
      setName(transcript);
      if (itemType === 'product' || itemType === 'drugstore') {
        processSpokenProductName(transcript);
      }
    }
  }, [itemType, processSpokenProductName]);

  const handleBarcodeScanned = useCallback(async (barcode: string) => {
    setIsBarcodeScannerOpen(false);
    setError(null);

    if (!isOffSearchEnabled) {
      setError(t('form.error.offSearchDisabled'));
      return;
    }

    setIsLoading(true);
    try {
      // Use smart fetcher (Food -> fallback Beauty)
      const productData = await fetchProductFromOpenDatabase(barcode);

      let finalName = productData.name || '';
      let finalTags = productData.tags || [];
      let finalIngredients = productData.ingredients || [];
      let finalAllergens = productData.allergens || [];

      if (language !== 'en' && isAiAvailable) {
        const textsToTranslate = [finalName, ...finalTags, ...finalIngredients, ...finalAllergens];
        try {
          const translated = await translateTexts(textsToTranslate, language);
          let currentIndex = 0;
          finalName = translated[currentIndex++];
          finalTags = translated.slice(currentIndex, currentIndex + finalTags.length);
          currentIndex += finalTags.length;
          finalIngredients = translated.slice(currentIndex, currentIndex + finalIngredients.length);
          currentIndex += finalIngredients.length;
          finalAllergens = translated.slice(currentIndex, currentIndex + finalAllergens.length);
        } catch (e) {
          console.error("Failed to translate OFF results for form", e);
        }
      }

      setName(finalName);
      setTags(finalTags.join(', '));
      setNutriScore((productData.nutriScore?.toUpperCase() as NutriScore) || '');
      setCalories(productData.calories !== undefined && productData.calories !== null ? productData.calories : '');
      setPurchaseLocation(productData.purchaseLocation?.join(', ') || '');
      setImage(productData.image || null);
      setIngredients(finalIngredients);
      setAllergens(finalAllergens);
      setDietary({
        isLactoseFree: productData.isLactoseFree || false,
        isVegan: productData.isVegan || false,
        isGlutenFree: productData.isGlutenFree || false,
      });

      // Auto-switch item type based on API Result
      if (productData.itemType === 'drugstore') {
          setItemType('drugstore');
          setCategory('personal_care');
      } else {
          setItemType('product');
          setCategory('other'); 
      }

      setAutoExpandDetails(true);

    } catch(e) {
       console.error(e);
       const errorMessage = e instanceof Error ? e.message : t('form.error.barcodeError');
       setError(errorMessage);
    } finally {
        setIsLoading(false);
    }
  }, [isOffSearchEnabled, t, language, isAiAvailable]);

  const textsNeedTranslation = useCallback((data: {name:string, tags:string[], ingredients:string[], allergens:string[]}) => {
    return data.name || data.tags.length > 0 || data.ingredients.length > 0 || data.allergens.length > 0;
  }, []);

  const handleImageFromCamera = useCallback(async (imageDataUrl: string) => {
    setIsCameraOpen(false);
    setError(null);

    if (!isAiAvailable) {
      setUncroppedImage(imageDataUrl);
      setSuggestedCrop(null);
      setIsCropperOpen(true);
      return;
    }

    if (scanMode === 'main') {
      let progressInterval: number | undefined;
      try {
        const progressMessages = [
            t('form.aiProgress.readingName'),
            t('form.aiProgress.findingScore'),
            t('form.aiProgress.generatingTags'),
            t('form.aiProgress.locatingProduct')
        ];

        setAnalysisProgress({ active: true, message: progressMessages[0] });
        let messageIndex = 0;
        progressInterval = window.setInterval(() => {
            messageIndex = (messageIndex + 1) % progressMessages.length;
            setAnalysisProgress(prev => ({ ...prev, message: progressMessages[messageIndex] }));
        }, 1500);

        // API Call now returns the optimized image alongside data
        const aiResult = await analyzeFoodImage(imageDataUrl);

        if(progressInterval) clearInterval(progressInterval);

        let mergedData = {
            name: aiResult.name || '',
            tags: aiResult.tags || [],
            nutriScore: (aiResult.nutriScore || '') as NutriScore | '',
            ingredients: [] as string[],
            allergens: [] as string[],
            isLactoseFree: false,
            isVegan: false,
            isGlutenFree: false,
        };

        if (language !== 'en' && textsNeedTranslation(mergedData)) {
            const textsToTranslate = [
                mergedData.name, ...mergedData.tags
            ];
            try {
                const translated = await translateTexts(textsToTranslate, language);
                if (translated.length === textsToTranslate.length) {
                    let i = 0;
                    mergedData.name = translated[i++];
                    mergedData.tags = translated.slice(i, i + mergedData.tags.length);
                }
            } catch (e) {
                console.error("Failed to translate AI results", e);
            }
        }

        // Resetting state with new image data - STRICT OVERWRITE
        setName(mergedData.name);
        setTags(mergedData.tags.join(', '));
        setNutriScore(mergedData.nutriScore);

        // Critical Fix: Explicitly reset potentially stale data from previous scans
        setCalories('');
        setIngredients([]);
        setAllergens([]);
        setDietary({ isLactoseFree: false, isVegan: false, isGlutenFree: false });

        // Handle Item Type & Category from AI
        let currentItemType: FoodItemType = 'product';

        if (aiResult.itemType) {
             if (aiResult.itemType === 'dish') {
                 setItemType('dish');
                 setCategory('restaurant_food');
                 currentItemType = 'dish';
             } else if (aiResult.itemType === 'drugstore') {
                 setItemType('drugstore');
                 setCategory('personal_care');
                 currentItemType = 'drugstore';
             } else {
                 setItemType('product');
                 setCategory(aiResult.category || 'other');
                 currentItemType = 'product';
             }
        }

        const newHighlightedFields: string[] = [];
        if (mergedData.name) newHighlightedFields.push('name');
        if (mergedData.tags.length > 0) newHighlightedFields.push('tags');
        if (mergedData.nutriScore) newHighlightedFields.push('nutriScore');
        if (aiResult.category) newHighlightedFields.push('category');
        setHighlightedFields(newHighlightedFields);

        if (mergedData.nutriScore || mergedData.tags.length > 0) setAutoExpandDetails(true);

        // FIX: Use the optimized image for the cropper to ensure coordinates align
        setUncroppedImage(aiResult.image || imageDataUrl);
        setSuggestedCrop(aiResult.boundingBox);
        setIsCropperOpen(true);
        setIsLoading(false);

        if (currentItemType === 'dish') {
            handleFindNearby();
        } else if (mergedData.name && isOffSearchEnabled) {
            setAnalysisProgress({ active: true, message: t('form.aiProgress.searchingDatabase') });

            try {
                // Pass currentItemType so we search the correct database (Food vs Beauty)
                const offResult = await searchProductByNameFromOpenDatabase(mergedData.name, currentItemType, language);

                // Merge tags (keep visual tags, add DB tags)
                setTags(prev => {
                    const existing = prev ? prev.split(',').map(s => s.trim()) : [];
                    const newTags = offResult.tags || [];
                    const combined = Array.from(new Set([...existing, ...newTags]));
                    return combined.join(', ');
                });

                // Strictly overwrite metadata with database results.
                setNutriScore((offResult.nutriScore as NutriScore) || '');
                // Correctly handle 0 kcal. 
                setCalories((offResult.calories !== undefined && offResult.calories !== null) ? offResult.calories : '');
                setIngredients(offResult.ingredients || []);
                setAllergens(offResult.allergens || []);
                setDietary({
                    isLactoseFree: !!offResult.isLactoseFree,
                    isVegan: !!offResult.isVegan,
                    isGlutenFree: !!offResult.isGlutenFree,
                });

                setHighlightedFields(prev => {
                    const next = [...prev];
                    if (offResult.nutriScore && !prev.includes('nutriScore')) next.push('nutriScore');
                    if (offResult.calories !== undefined && !prev.includes('calories')) next.push('calories');
                    if ((offResult.tags?.length || 0) > 0 && !prev.includes('tags')) next.push('tags');
                    return next;
                });

                setAutoExpandDetails(true);

            } catch (offError) {
                console.warn("Could not fetch supplementary data from Open Database:", offError);
            } finally {
                setAnalysisProgress({ active: false, message: '' });
            }
        } else {
             setAnalysisProgress({ active: false, message: '' });
        }

      } catch (e) {
        if(progressInterval) clearInterval(progressInterval);
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : t('form.error.genericAiError');
        setError(errorMessage);
        setUncroppedImage(imageDataUrl);
        setSuggestedCrop(null);
        setIsCropperOpen(true);
        setAnalysisProgress({ active: false, message: '' });
      } 
    } else { // scanMode === 'ingredients'
      setIngredientsLoading(true);
      try {
        const result = await analyzeIngredientsImage(imageDataUrl);

        let finalIngredients = result.ingredients || [];
        let finalAllergens = result.allergens || [];

        if (language !== 'en' && (finalIngredients.length > 0 || finalAllergens.length > 0)) {
            try {
                const textsToTranslate = [...finalIngredients, ...finalAllergens];
                const translated = await translateTexts(textsToTranslate, language);
                if (translated.length === textsToTranslate.length) {
                    finalIngredients = translated.slice(0, finalIngredients.length);
                    finalAllergens = translated.slice(finalIngredients.length);
                }
            } catch(e) {
                console.error("Failed to translate ingredients AI results for form", e);
            }
        }

        setIngredients(finalIngredients);
        setAllergens(finalAllergens);
        setDietary({
            isLactoseFree: result.isLactoseFree,
            isVegan: result.isVegan,
            isGlutenFree: result.isGlutenFree,
        });
        setAutoExpandDetails(true);
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : t('form.error.ingredientsAiError');
        setError(errorMessage);
      } finally {
        setIngredientsLoading(false);
      }
    }
  }, [isAiAvailable, scanMode, t, isOffSearchEnabled, language, textsNeedTranslation, handleFindNearby]);

  const handleCropComplete = useCallback((croppedImageUrl: string) => {
    setImage(croppedImageUrl);
    setIsCropperOpen(false);
    setUncroppedImage(null);
    setSuggestedCrop(null);
  }, []);

  const handleCropCancel = useCallback(() => {
    if (uncroppedImage) setImage(uncroppedImage);
    setIsCropperOpen(false);
    setUncroppedImage(null);
    setSuggestedCrop(null);
  }, [uncroppedImage]);

  const handleFileChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setScanMode('main');
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleImageFromCamera(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  }, [handleImageFromCamera]);

  const handleDietaryChange = useCallback((key: keyof typeof dietary) => {
    setDietary(prev => ({...prev, [key]: !prev[key]}));
  }, []);

  const removeImage = useCallback(() => {
    setImage(null);
    if(fileInputRef.current) fileInputRef.current.value = '';
  }, []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!name.trim()) {
      setError(t('form.error.nameAndRating'));
      return;
    }
    if (rating === 0) {
      setError(t('form.error.nameAndRating'));
      return;
    }

    const commonData = {
      name,
      rating,
      notes: notes || undefined,
      image: image || undefined,
      tags: tags ? tags.split(',').map(tag => tag.trim()).filter(Boolean) : undefined,
      itemType,
      // CRITICAL: Force category to be present. If empty string or undefined, use 'other'.
      category: category || 'other', 
      isFamilyFavorite,
      // Pass price for all types, allowing products to have a price too
      price: price !== '' ? Number(price) : undefined,
      expiryDate: expiryDate || undefined,
    };

    if (itemType === 'product' || itemType === 'drugstore') {
        onSaveItem({
          ...commonData,
          nutriScore: nutriScore || undefined,
          calories: calories !== '' ? Number(calories) : undefined,
          purchaseLocation: purchaseLocation ? purchaseLocation.split(',').map(loc => loc.trim()).filter(Boolean) : undefined,
          ingredients: ingredients.length > 0 ? ingredients : undefined,
          allergens: allergens.length > 0 ? allergens : undefined,
          isLactoseFree: dietary.isLactoseFree,
          isVegan: dietary.isVegan,
          isGlutenFree: dietary.isGlutenFree,
        });
    } else { // itemType === 'dish'
        onSaveItem({
          ...commonData,
          restaurantName: restaurantName || undefined,
          cuisineType: cuisineType || undefined,
        });
    }
  }, [name, rating, t, notes, image, tags, itemType, category, onSaveItem, nutriScore, calories, purchaseLocation, ingredients, allergens, dietary, restaurantName, cuisineType, price, isFamilyFavorite, expiryDate]);

  const handleSelectRestaurant = useCallback((restaurantIndex: number) => {
      const selected = nearbyRestaurants[restaurantIndex];
      if(selected) {
          setRestaurantName(selected.name);
          if (selected.cuisine) {
              setCuisineType(selected.cuisine);
          }
          setNearbyRestaurants([]); 
      }
  }, [nearbyRestaurants]);

  return {
    formState: {
      name, rating, notes, image, tags, isFamilyFavorite, category,
      nutriScore, calories, purchaseLocation, ingredients, allergens, dietary,
      restaurantName, cuisineType, price, itemType, expiryDate
    },
    formSetters: {
      setName, setRating, setNotes, setImage, setTags, setIsFamilyFavorite, setCategory,
      setNutriScore, setCalories, setPurchaseLocation, setIngredients, setAllergens, setRestaurantName, setCuisineType, setPrice, setItemType, setAutoExpandDetails, setExpiryDate
    },
    uiState: {
      isCameraOpen, isBarcodeScannerOpen, isSpeechModalOpen, isNameSearchLoading,
      isCropperOpen, uncroppedImage, suggestedCrop, isLoading, analysisProgress,
      highlightedFields, isIngredientsLoading, error, isFindingRestaurants,
      nearbyRestaurants, locationError, isAiAvailable, scanMode, autoExpandDetails
    },
    uiSetters: {
      setIsCameraOpen, setIsBarcodeScannerOpen, setIsSpeechModalOpen, setIsCropperOpen, setError
    },
    actions: {
      handleScanMainImage, handleScanIngredients, handleBarcodeScanned,
      handleImageFromCamera, handleDictationResult, handleCropComplete,
      handleCropCancel, handleFileChange, handleDietaryChange, handleFindNearby,
      handleSelectRestaurant, removeImage, handleSubmit
    },
    fileInputRef
  };
};

import React from 'react';
import { useTranslation } from '../../i18n/index';
import { useAppSettings } from '../../contexts/AppSettingsContext';
import { StoreLogo } from '../StoreLogo';
import { GroceryCategory, NutriScore } from '../../types';
import { 
    CategoryProduceIcon, CategoryBakeryIcon, CategoryMeatIcon, CategoryDairyIcon, 
    CategoryPantryIcon, CategoryFrozenIcon, CategorySnacksIcon, CategoryBeveragesIcon, 
    CategoryHouseholdIcon, CategoryPersonalCareIcon, CategoryOtherIcon,
    CategoryRestaurantIcon, SparklesIcon
} from '../Icons';

interface ProductMetadataSectionProps {
  formState: any;
  formSetters: any;
  uiState: any;
  itemType: string;
}

const nutriScoreOptions: NutriScore[] = ['A', 'B', 'C', 'D', 'E'];
const nutriScoreColors: Record<NutriScore, string> = {
  A: 'bg-green-600',
  B: 'bg-lime-600',
  C: 'bg-yellow-500',
  D: 'bg-orange-500',
  E: 'bg-red-600',
};

const groceryCategories: GroceryCategory[] = [
    'produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 
    'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'
];

const CategoryIconMap: Record<GroceryCategory, React.FC<{ className?: string }>> = {
    'produce': CategoryProduceIcon,
    'bakery': CategoryBakeryIcon,
    'meat_fish': CategoryMeatIcon,
    'dairy_eggs': CategoryDairyIcon,
    'pantry': CategoryPantryIcon,
    'frozen': CategoryFrozenIcon,
    'snacks': CategorySnacksIcon,
    'beverages': CategoryBeveragesIcon,
    'household': CategoryHouseholdIcon,
    'personal_care': CategoryPersonalCareIcon,
    'restaurant_food': CategoryRestaurantIcon,
    'other': CategoryOtherIcon,
};

const CategoryColorMap: Record<GroceryCategory, string> = {
    'produce': 'bg-green-100 text-green-700 dark:bg-green-900/50 dark:text-green-300',
    'bakery': 'bg-amber-100 text-amber-700 dark:bg-amber-900/50 dark:text-amber-300',
    'meat_fish': 'bg-red-100 text-red-700 dark:bg-red-900/50 dark:text-red-300',
    'dairy_eggs': 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/50 dark:text-yellow-300',
    'pantry': 'bg-orange-100 text-orange-700 dark:bg-orange-900/50 dark:text-orange-300',
    'frozen': 'bg-sky-100 text-sky-700 dark:bg-sky-900/50 dark:text-sky-300',
    'snacks': 'bg-pink-100 text-pink-700 dark:bg-pink-900/50 dark:text-pink-300',
    'beverages': 'bg-blue-100 text-blue-700 dark:bg-blue-900/50 dark:text-blue-300',
    'household': 'bg-gray-200 text-gray-700 dark:bg-gray-700 dark:text-gray-300',
    'personal_care': 'bg-purple-100 text-purple-700 dark:bg-purple-900/50 dark:text-purple-300',
    'restaurant_food': 'bg-teal-100 text-teal-700 dark:bg-teal-900/50 dark:text-teal-300',
    'other': 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400',
};

export const ProductMetadataSection: React.FC<ProductMetadataSectionProps> = ({
  formState,
  formSetters,
  uiState,
  itemType
}) => {
  const { t } = useTranslation();
  const { savedShops } = useAppSettings();

  const toggleShop = (shop: string) => {
    const currentShops = formState.purchaseLocation.split(',').map((s: string) => s.trim()).filter(Boolean);
    let newShops;
    if (currentShops.includes(shop)) {
        newShops = currentShops.filter((s: string) => s !== shop);
    } else {
        newShops = [...currentShops, shop];
    }
    formSetters.setPurchaseLocation(newShops.join(', '));
  };

  const isShopSelected = (shop: string) => {
    const currentShops = formState.purchaseLocation.split(',').map((s: string) => s.trim()).filter(Boolean);
    return currentShops.includes(shop);
  };

  return (
    <div className="space-y-4">
      {/* Unified Category Selection */}
      <div className={`space-y-2 transition-shadow rounded-md p-1 ${uiState.highlightedFields.includes('category') ? 'highlight-ai' : ''}`}>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('form.category.title')}</label>
        <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
          {groceryCategories.map(cat => {
            const Icon = CategoryIconMap[cat];
            const isSelected = formState.category === cat;
            return (
              <button
                key={cat}
                type="button"
                onClick={() => formSetters.setCategory(cat)}
                className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${isSelected ? 'ring-2 ring-indigo-500 shadow-md scale-105' : 'hover:bg-gray-100 dark:hover:bg-gray-700/50 opacity-70 hover:opacity-100'} ${isSelected ? CategoryColorMap[cat] : 'bg-gray-50 dark:bg-gray-800 text-gray-500 dark:text-gray-400'}`}
                title={t(`category.${cat}`)}
              >
                <Icon className="w-6 h-6 mb-1" />
                <span className="text-[10px] font-medium truncate w-full text-center">{t(`category.${cat}`)}</span>
              </button>
            )
          })}
        </div>
      </div>

      {/* Purchase Location */}
      {itemType !== 'dish' && (
        <div className="flex flex-col gap-4">
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Einkaufsort</label>
                <input
                type="text"
                placeholder={t('form.placeholder.purchaseLocation')}
                value={formState.purchaseLocation}
                onChange={e => formSetters.setPurchaseLocation(e.target.value)}
                className="w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-3"
                />
                {savedShops.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-2">
                    {savedShops.map(shop => {
                    const isSelected = isShopSelected(shop);
                    return (
                        <button
                        key={shop}
                        type="button"
                        onClick={() => toggleShop(shop)}
                        className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-xs border transition-colors ${isSelected ? 'bg-indigo-100 dark:bg-indigo-900/50 border-indigo-300 dark:border-indigo-700' : 'bg-gray-50 dark:bg-gray-700/50 border-gray-200 dark:border-gray-600 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
                        >
                        <StoreLogo name={shop} size="sm" />
                        <span className={isSelected ? 'font-semibold text-indigo-800 dark:text-indigo-200' : 'text-gray-600 dark:text-gray-300'}>{shop}</span>
                        </button>
                    );
                    })}
                </div>
                )}
            </div>
        </div>
      )}

      {/* NutriScore, Calories & Price (Product Only) */}
      {itemType === 'product' && (
        <>
        <div className="flex flex-col sm:flex-row gap-4">
            {/* NutriScore */}
            <div className={`p-2 rounded-md transition-shadow flex-1 ${uiState.highlightedFields.includes('nutriScore') ? 'highlight-ai' : ''}`}>
                <div className="flex items-center gap-2 mb-1">
                    <label className="text-sm font-medium text-gray-700 dark:text-gray-300">{t('form.label.nutriScore')}</label>
                </div>
                <div className="flex items-center gap-2 flex-wrap">
                {nutriScoreOptions.map(score => (
                    <button
                    type="button"
                    key={score}
                    onClick={() => formSetters.setNutriScore((current: string) => current === score ? '' : score)}
                    className={`w-8 h-8 rounded-full text-white font-bold flex items-center justify-center transition-transform transform ${nutriScoreColors[score]} ${formState.nutriScore === score ? 'ring-2 ring-indigo-500 dark:ring-indigo-400 ring-offset-2 ring-offset-white dark:ring-offset-gray-800 scale-110' : 'hover:scale-105'}`}
                    aria-pressed={formState.nutriScore === score}
                    aria-label={t('form.aria.selectNutriScore', { score })}
                    >
                    {score}
                    </button>
                ))}
                </div>
            </div>

            {/* Calories */}
            <div className={`p-2 rounded-md transition-shadow flex-1 ${uiState.highlightedFields.includes('calories') ? 'highlight-ai' : ''}`}>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Kcal / 100g</label>
                <div className="relative">
                    <input
                        type="number"
                        placeholder="0"
                        value={formState.calories}
                        onChange={e => formSetters.setCalories(e.target.value === '' ? '' : parseInt(e.target.value, 10))}
                        className="w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2 pl-8"
                    />
                    <div className="absolute inset-y-0 left-0 flex items-center pl-2 pointer-events-none">
                        <span className="text-orange-500">🔥</span>
                    </div>
                </div>
            </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
            {/* Price (Manual) */}
            <div className="p-2 rounded-md transition-shadow flex-1">
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Preis (€)</label>
                <input
                    type="number"
                    placeholder="0.00"
                    step="0.01"
                    value={formState.price}
                    onChange={e => formSetters.setPrice(e.target.value === '' ? '' : parseFloat(e.target.value))}
                    className="w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2"
                />
            </div>

            {/* Expiry Date */}
            <div className="p-2 rounded-md transition-shadow flex-1">
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('form.label.expiryDate')}</label>
                <input
                    type="date"
                    value={formState.expiryDate}
                    onChange={e => formSetters.setExpiryDate(e.target.value)}
                    className="w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2"
                />
            </div>
        </div>
        </>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { FoodItem, NutriScore } from '../types';
import { StarIcon, TrashIcon, LactoseFreeIcon, VeganIcon, GlutenFreeIcon, ShoppingBagIcon, BuildingStorefrontIcon, UserGroupIcon, LockClosedIcon, ShoppingCartIcon, BeakerIcon } from './Icons';
import { useTranslation } from '../i18n/index';
import { useTranslatedItem } from '../hooks/useTranslatedItem';
import { StoreLogo } from './StoreLogo';
import { useAuth } from '../contexts/AuthContext';
import { triggerHaptic } from '../utils/haptics';

interface FoodItemCardProps {
  item: FoodItem;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  onViewDetails: (item: FoodItem) => void;
  onAddToShoppingList: (item: FoodItem) => void;
  onToggleFamilyStatus?: (item: FoodItem) => void;
  isPreview?: boolean;
  isInShoppingList?: boolean;
}

const nutriScoreColors: Record<NutriScore, string> = {
  A: 'bg-green-600',
  B: 'bg-lime-600',
  C: 'bg-yellow-500',
  D: 'bg-orange-500',
  E: 'bg-red-600',
};

const DietaryIcon: React.FC<{ type: 'lactoseFree' | 'vegan' | 'glutenFree', className?: string }> = ({ type, className }) => {
    const { t } = useTranslation();
    const icons = {
        lactoseFree: <LactoseFreeIcon className={`${className} text-blue-600 dark:text-blue-400`} />,
        vegan: <VeganIcon className={`${className}`} />,
        glutenFree: <GlutenFreeIcon className={`${className}`} />,
    };
    const tooltips = {
        lactoseFree: t('card.lactoseFreeTooltip'),
        vegan: t('card.veganTooltip'),
        glutenFree: t('card.glutenFreeTooltip'),
    };
    return (
        <div className="relative group flex items-center justify-center">
            {icons[type]}
            <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max px-2 py-1 bg-gray-800 text-white text-xs rounded-md opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-10">
                {tooltips[type]}
            </span>
        </div>
    );
}

// Internal component for the actual content
const FoodItemCardContent: React.FC<FoodItemCardProps> = ({ item, onDelete, onEdit, onViewDetails, onAddToShoppingList, onToggleFamilyStatus, isPreview = false, isInShoppingList = false }) => {
  const { t, language } = useTranslation();
  const { user } = useAuth();
  const displayItem = useTranslatedItem(item);

  // Swipe State
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchOffset, setTouchOffset] = useState(0);
  const SWIPE_THRESHOLD = 80;

  if (!displayItem) {
    return null;
  }

  const hasDietaryOrAllergens = displayItem.itemType === 'product' && (displayItem.isLactoseFree || displayItem.isVegan || displayItem.isGlutenFree || (displayItem.allergens && displayItem.allergens.length > 0));
  const hasTags = displayItem.tags && displayItem.tags.length > 0;
  // If not a preview, the card is clickable to Edit
  const isClickable = !isPreview;
  const isFamilyShared = displayItem.isFamilyFavorite;
  const isOwner = user?.id === displayItem.user_id;

  const getPlaceholderIcon = () => {
      switch(displayItem.itemType) {
          case 'dish': return <BuildingStorefrontIcon className="w-6 h-6 text-gray-400/50"/>;
          case 'drugstore': return <BeakerIcon className="w-6 h-6 text-gray-400/50"/>;
          default: return <ShoppingBagIcon className="w-6 h-6 text-gray-400/50"/>;
      }
  };

  const getStatusIcon = () => {
      switch(displayItem.itemType) {
          case 'dish': return <BuildingStorefrontIcon className="w-2.5 h-2.5" />;
          case 'drugstore': return <BeakerIcon className="w-2.5 h-2.5" />;
          default: return null;
      }
  };

  // Expiry Logic
  let expiryStatus: 'expired' | 'soon' | 'ok' | null = null;
  let daysUntilExpiry = 0;

  if (displayItem.expiryDate) {
      const today = new Date();
      today.setHours(0,0,0,0);
      const exp = new Date(displayItem.expiryDate);
      exp.setHours(0,0,0,0);
      const diffTime = exp.getTime() - today.getTime();
      daysUntilExpiry = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (daysUntilExpiry < 0) expiryStatus = 'expired';
      else if (daysUntilExpiry <= 3) expiryStatus = 'soon';
      else expiryStatus = 'ok';
  }

  const statusIcon = getStatusIcon();

  let borderClass = 'border-gray-100 dark:border-gray-700';
  let ringClass = '';

  if (isFamilyShared) {
      borderClass = 'border-amber-200 dark:border-amber-800';
      ringClass = 'ring-1 ring-amber-100 dark:ring-amber-900/30';
  }

  // Swipe Handlers
  const onTouchStart = (e: React.TouchEvent) => {
      if (isPreview) return;
      setTouchStart(e.targetTouches[0].clientX);
  };

  const onTouchMove = (e: React.TouchEvent) => {
      if (touchStart === null || isPreview) return;
      const currentTouch = e.targetTouches[0].clientX;
      const diff = currentTouch - touchStart;
      if (diff < 0) {
          setTouchOffset(Math.max(diff, -150));
      }
  };

  const onTouchEnd = () => {
      if (touchStart === null || isPreview) return;
      if (touchOffset < -SWIPE_THRESHOLD) {
          triggerHaptic('warning');
          onDelete(item.id);
          setTouchOffset(0); 
      } else {
          setTouchOffset(0);
      }
      setTouchStart(null);
  };

  const handleCardClick = () => {
      if (Math.abs(touchOffset) > 5) return;

      if (isPreview) {
          // In preview mode (e.g. Discover or Duplicate check)
          if (onViewDetails) onViewDetails(item);
      } else {
          // In Dashboard, view Details (which allows Edit)
          onViewDetails(item);
      }
  };

  return (
    <div className={`relative h-24 sm:h-28 w-full select-none touch-pan-y rounded-xl ${isPreview ? '' : 'overflow-hidden'}`}>

        {/* Background Action Layer */}
        {!isPreview && (
            <div 
                className="absolute inset-0 bg-red-500 flex items-center justify-end pr-6 rounded-xl transition-opacity duration-200"
                style={{ opacity: Math.abs(touchOffset) > 20 ? 1 : 0 }}
            >
                <TrashIcon className="w-6 h-6 text-white" />
            </div>
        )}

        {/* Foreground Card */}
        <div 
            className={`group bg-white dark:bg-gray-800 rounded-xl shadow-sm border overflow-hidden transition-transform duration-200 relative flex flex-row h-full w-full ${isClickable ? 'cursor-pointer' : ''} ${borderClass} ${ringClass}`}
            style={{ transform: `translateX(${touchOffset}px)` }}
            onTouchStart={onTouchStart}
            onTouchMove={onTouchMove}
            onTouchEnd={onTouchEnd}
            onClick={handleCardClick}
        >
            {/* Left Side: Image */}
            <div className="relative aspect-square h-full shrink-0 bg-gray-50 dark:bg-gray-700/50 overflow-hidden">
                {displayItem.image ? (
                    <img 
                        src={displayItem.image} 
                        alt={displayItem.name} 
                        loading="lazy"
                        className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" 
                    />
                ) : (
                    <div className="w-full h-full flex items-center justify-center bg-gray-100 dark:bg-gray-700/50">
                        {getPlaceholderIcon()}
                    </div>
                )}

                {/* Top Left Status Overlay */}
                <div className="absolute top-1 left-1 flex flex-col gap-1">
                    {statusIcon && (
                        <div className="bg-white/90 dark:bg-black/60 backdrop-blur-md p-0.5 rounded-full text-gray-700 dark:text-gray-200 shadow-sm border border-black/5 dark:border-white/10">
                            {statusIcon}
                        </div>
                    )}

                    <button
                        type="button" 
                        className={`backdrop-blur-md p-0.5 rounded-full shadow-sm transition-all duration-200 border border-black/5 dark:border-white/10 ${isFamilyShared ? 'bg-amber-100/90 text-amber-700 dark:bg-amber-900/80 dark:text-amber-300' : 'bg-white/90 text-gray-400 dark:bg-black/60 dark:text-gray-400'} ${isOwner && !isPreview ? 'cursor-pointer hover:scale-110 active:scale-95' : ''}`}
                        onClick={(e) => {
                            if (isOwner && !isPreview && onToggleFamilyStatus) {
                                e.stopPropagation();
                                onToggleFamilyStatus(item);
                            }
                        }}
                        disabled={!isOwner || isPreview}
                    >
                        {isFamilyShared ? <UserGroupIcon className="w-2.5 h-2.5" /> : <LockClosedIcon className="w-2.5 h-2.5" />}
                    </button>
                </div>

                {/* NutriScore */}
                {displayItem.itemType === 'product' && displayItem.nutriScore && (
                    <div className={`absolute bottom-1 right-1 text-[9px] w-4 h-4 rounded-full text-white font-bold flex items-center justify-center shadow-sm border border-white/20 ${nutriScoreColors[displayItem.nutriScore]}`}>
                        {displayItem.nutriScore}
                    </div>
                )}
            </div>

            {/* Right Side: Content - Compact Layout */}
            <div className="flex-1 flex flex-col justify-between p-2 min-w-0 relative">

                <div>
                    <div className="flex justify-between items-start gap-1">
                        <h3 className="text-sm sm:text-base font-bold text-gray-900 dark:text-white truncate leading-tight tracking-tight" title={displayItem.name}>
                            {displayItem.name}
                        </h3>

                        {!isPreview && (
                            <div className="flex items-center gap-0.5 -mr-1 -mt-1 shrink-0">
                                {displayItem.itemType !== 'dish' && (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); onAddToShoppingList(item); }}
                                        className={`p-1 rounded-full transition-all duration-200 ${
                                            isInShoppingList 
                                            ? 'bg-indigo-600 text-white shadow-sm' 
                                            : 'text-gray-400 hover:bg-indigo-50 hover:text-indigo-600 dark:hover:bg-indigo-900/30 dark:hover:text-indigo-300'
                                        }`}
                                    >
                                        {isInShoppingList ? <ShoppingCartIcon className="w-3.5 h-3.5" /> : <ShoppingBagIcon className="w-3.5 h-3.5" />}
                                    </button>
                                )}
                            </div>
                        )}
                    </div>

                    <div className="flex items-center gap-0.5 mt-0.5">
                        {[1, 2, 3, 4, 5].map(star => (
                            <StarIcon key={star} className={`w-3 h-3 ${displayItem.rating >= star ? 'text-yellow-400 fill-current' : 'text-gray-200 dark:text-gray-700'}`} filled={displayItem.rating >= star} />
                        ))}
                    </div>

                    <div className="mt-1 min-h-[1rem] flex items-center justify-between">
                        <div className="overflow-hidden flex-1 flex items-center">
                            {displayItem.itemType === 'dish' && displayItem.restaurantName && (
                                <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate italic flex items-center gap-1">
                                    <BuildingStorefrontIcon className="w-2.5 h-2.5"/> {displayItem.restaurantName}
                                </p>
                            )}

                            {(displayItem.itemType === 'product' || displayItem.itemType === 'drugstore') && displayItem.purchaseLocation && displayItem.purchaseLocation.length > 0 && (
                                <div className="flex items-center gap-0.5 overflow-hidden">
                                    {displayItem.purchaseLocation.slice(0, 3).map((loc, idx) => (
                                        <StoreLogo key={idx} name={loc} size="sm" showName={false} className="w-3.5 h-3.5 opacity-80 grayscale-[0.3]" />
                                    ))}
                                    {displayItem.purchaseLocation.length > 3 && (
                                        <span className="text-[9px] text-gray-400">+{displayItem.purchaseLocation.length - 3}</span>
                                    )}
                                </div>
                            )}
                        </div>

                        {/* PRICE & EXPIRY BADGES */}
                        <div className="flex gap-1 shrink-0 ml-1">
                            {/* EXPIRY BADGE */}
                            {expiryStatus && (
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded whitespace-nowrap border ${
                                    expiryStatus === 'expired' 
                                        ? 'bg-red-100 text-red-700 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-800' 
                                        : expiryStatus === 'soon' 
                                            ? 'bg-yellow-100 text-yellow-800 border-yellow-200 dark:bg-yellow-900/30 dark:text-yellow-300 dark:border-yellow-800' 
                                            : 'bg-gray-100 text-gray-500 border-gray-200 dark:bg-gray-800 dark:text-gray-400 dark:border-gray-700'
                                }`} title={displayItem.expiryDate}>
                                    {expiryStatus === 'expired' ? t('card.expired') : daysUntilExpiry === 0 ? t('card.expiresToday') : t('card.expiresIn', { days: daysUntilExpiry })}
                                </span>
                            )}

                            {/* PRICE BADGE */}
                            {typeof displayItem.price === 'number' && displayItem.price > 0 && (
                                <span className="text-[10px] font-bold text-gray-700 dark:text-gray-300 bg-gray-100 dark:bg-gray-700/50 px-1.5 py-0.5 rounded whitespace-nowrap border border-gray-200 dark:border-gray-600">
                                    {displayItem.price.toFixed(2)}€
                                </span>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Row: Tags & Dietary Badges */}
                <div className="flex items-end justify-between gap-2 overflow-hidden h-5">
                    {hasTags ? (
                        <div className="flex gap-1 overflow-x-auto scrollbar-hide py-0.5 mask-linear-fade w-full">
                            {displayItem.tags!.map(tag => (
                            <span key={tag} className="flex-shrink-0 bg-gray-50 text-gray-500 dark:bg-gray-700/50 dark:text-gray-400 text-[9px] font-medium px-1.5 py-0 rounded-full border border-gray-100 dark:border-gray-700 whitespace-nowrap">
                                {tag}
                            </span>
                            ))}
                        </div>
                    ) : <div />}

                    {hasDietaryOrAllergens && (
                        <div className="flex items-center gap-0.5 flex-shrink-0 pl-1 bg-gradient-to-l from-white via-white to-transparent dark:from-gray-800 dark:via-gray-800">
                            {displayItem.isLactoseFree && <DietaryIcon type="lactoseFree" className="w-3.5 h-3.5" />}
                            {displayItem.isVegan && <DietaryIcon type="vegan" className="w-3.5 h-3.5" />}
                            {displayItem.isGlutenFree && <DietaryIcon type="glutenFree" className="w-3.5 h-3.5" />}
                            {displayItem.allergens && displayItem.allergens.length > 0 && !displayItem.isVegan && !displayItem.isGlutenFree && (
                                <span className="text-[9px] font-bold text-orange-500 border border-orange-200 dark:border-orange-800 rounded px-0.5" title="Allergens">!</span>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
        <style>{`
            .scrollbar-hide::-webkit-scrollbar { display: none; }
            .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
            .mask-linear-fade {
                mask-image: linear-gradient(to right, black 85%, transparent 100%);
                -webkit-mask-image: linear-gradient(to right, black 85%, transparent 100%);
            }
        `}</style>
    </div>
  );
};

